export default "<template>\r\n  <FlowDesignerLayout\r\n    @ready=\"handleReady\"\r\n  />\r\n</template>\r\n\r\n<script setup lang=\"ts\">\r\nimport { message } from 'ant-design-vue'\r\nimport { FlowDesignerLayout }  from '@quick-code/x6-flow-designer'\r\nimport type { FlowDesigner } from '@quick-code/x6-flow-designer'\r\nimport type { Node } from '@antv/x6'\r\n\r\n/**\r\n * ready 回调：覆盖内置节点状态并初始化画布\r\n */\r\nfunction handleReady(designer: FlowDesigner) {\r\n  const graph = designer.getGraph()\r\n\r\n  // ========== 覆盖 3 种内置节点状态 ==========\r\n\r\n  // 1. 覆盖 default 状态：淡蓝色边框\r\n  designer.registerNodeStateHandler('default', {\r\n    apply(node) {\r\n      node.setAttrs({\r\n        body: {\r\n          stroke: '#3b82f6',\r\n          strokeWidth: 2,\r\n          fill: '#dbeafe',\r\n        },\r\n        label: {\r\n          fill: '#1e40af',\r\n          fontWeight: 'normal',\r\n        }\r\n      })\r\n    }\r\n  })\r\n\r\n  // 2. 覆盖 hover 状态：紫色加粗 + 阴影\r\n  designer.registerNodeStateHandler('hover', {\r\n    apply(node) {\r\n      node.setAttrs({\r\n        body: {\r\n          stroke: '#8b5cf6',\r\n          strokeWidth: 3,\r\n          fill: '#ede9fe',\r\n          filter: {\r\n            name: 'dropShadow',\r\n            args: { dx: 0, dy: 2, blur: 6, color: 'rgba(139, 92, 246, 0.4)' }\r\n          }\r\n        },\r\n        label: {\r\n          fill: '#5b21b6',\r\n          fontWeight: 'bold',\r\n        }\r\n      })\r\n    },\r\n    cleanup(node) {\r\n      node.setAttrs({\r\n        body: {\r\n          filter: null\r\n        }\r\n      })\r\n    }\r\n  })\r\n\r\n  // 3. 覆盖 selected 状态：青色粗边框 + 光晕\r\n  designer.registerNodeStateHandler('selected', {\r\n    apply(node) {\r\n      node.setAttrs({\r\n        body: {\r\n          stroke: '#06b6d4',\r\n          strokeWidth: 4,\r\n          fill: '#cffafe',\r\n          filter: {\r\n            name: 'dropShadow',\r\n            args: { dx: 0, dy: 0, blur: 8, color: 'rgba(6, 182, 212, 0.6)' }\r\n          }\r\n        },\r\n        label: {\r\n          fill: '#164e63',\r\n          fontWeight: 'bold',\r\n          fontSize: 14,\r\n        }\r\n      })\r\n    },\r\n    cleanup(node) {\r\n      node.setAttrs({\r\n        body: {\r\n          filter: null\r\n        }\r\n      })\r\n    }\r\n  })\r\n\r\n  // ========== 新增自定义状态 ==========\r\n\r\n  // 4. error 状态：红色粗边框 + 错误图标\r\n  designer.registerNodeStateHandler('error', {\r\n    apply(node) {\r\n      node.setAttrs({\r\n        body: {\r\n          stroke: '#ef4444',\r\n          strokeWidth: 4,\r\n          fill: '#fee2e2',\r\n          filter: {\r\n            name: 'dropShadow',\r\n            args: { dx: 0, dy: 2, blur: 8, color: 'rgba(239, 68, 68, 0.5)' }\r\n          }\r\n        },\r\n        label: {\r\n          fill: '#991b1b',\r\n          fontWeight: 'bold',\r\n        }\r\n      })\r\n\r\n      // 设置错误标记（可在插槽中使用）\r\n      const currentData = node.getData() || {}\r\n      node.setData({\r\n        ...currentData,\r\n        hasError: true,\r\n        errorMessage: '节点验证失败'\r\n      })\r\n    },\r\n    cleanup(node) {\r\n      // 恢复默认样式\r\n      node.setAttrs({\r\n        body: {\r\n          filter: null\r\n        }\r\n      })\r\n\r\n      // 清除错误标记\r\n      const currentData = node.getData() || {}\r\n      node.setData({\r\n        ...currentData,\r\n        hasError: false,\r\n        errorMessage: undefined\r\n      })\r\n    }\r\n  })\r\n\r\n  // ========== 创建演示节点 ==========\r\n\r\n  const node1 = graph.addNode({\r\n    id: 'node1',\r\n    shape: 'rect',\r\n    x: 80,\r\n    y: 80,\r\n    width: 140,\r\n    height: 70,\r\n    label: '默认状态',\r\n    attrs: {\r\n      label: {\r\n        fontSize: 14,\r\n      },\r\n    },\r\n  })\r\n  // 设置初始状态为 default\r\n  designer.setNodeState(node1, 'default')\r\n\r\n  const node2 = graph.addNode({\r\n    id: 'node2',\r\n    shape: 'rect',\r\n    x: 280,\r\n    y: 80,\r\n    width: 140,\r\n    height: 70,\r\n    label: '默认状态',\r\n    attrs: {\r\n      label: {\r\n        fontSize: 14,\r\n      },\r\n    },\r\n  })\r\n  designer.setNodeState(node2, 'default')\r\n\r\n  const node3 = graph.addNode({\r\n    id: 'node3',\r\n    shape: 'rect',\r\n    x: 480,\r\n    y: 80,\r\n    width: 140,\r\n    height: 70,\r\n    label: '默认状态',\r\n    attrs: {\r\n      label: {\r\n        fontSize: 14,\r\n      },\r\n    },\r\n  })\r\n  designer.setNodeState(node3, 'default')\r\n\r\n  const node4 = graph.addNode({\r\n    id: 'node4',\r\n    shape: 'rect',\r\n    x: 80,\r\n    y: 200,\r\n    width: 140,\r\n    height: 70,\r\n    label: '默认状态',\r\n    attrs: {\r\n      label: {\r\n        fontSize: 14,\r\n      },\r\n    },\r\n  })\r\n  designer.setNodeState(node4, 'default')\r\n\r\n  const node5 = graph.addNode({\r\n    id: 'node5',\r\n    shape: 'rect',\r\n    x: 280,\r\n    y: 200,\r\n    width: 140,\r\n    height: 70,\r\n    label: '默认状态',\r\n    attrs: {\r\n      label: {\r\n        fontSize: 14,\r\n      },\r\n    },\r\n  })\r\n  designer.setNodeState(node5, 'default')\r\n\r\n  const node6 = graph.addNode({\r\n    id: 'node6',\r\n    shape: 'rect',\r\n    x: 480,\r\n    y: 200,\r\n    width: 140,\r\n    height: 70,\r\n    label: '默认状态',\r\n    attrs: {\r\n      label: {\r\n        fontSize: 14,\r\n      },\r\n    },\r\n  })\r\n  designer.setNodeState(node6, 'default')\r\n\r\n  // ========== 添加连线 ==========\r\n\r\n  graph.addEdge({\r\n    id: 'edge1',\r\n    shape: 'flow-edge',\r\n    source: node1,\r\n    target: node2,\r\n    labels: ['流程1'],\r\n  })\r\n\r\n  graph.addEdge({\r\n    id: 'edge2',\r\n    shape: 'flow-edge',\r\n    source: node2,\r\n    target: node3,\r\n    labels: ['流程2'],\r\n  })\r\n\r\n  graph.addEdge({\r\n    id: 'edge3',\r\n    shape: 'flow-edge',\r\n    source: node1,\r\n    target: node4,\r\n    labels: ['流程3'],\r\n  })\r\n\r\n  graph.addEdge({\r\n    id: 'edge4',\r\n    shape: 'flow-edge',\r\n    source: node4,\r\n    target: node5,\r\n    labels: ['流程4'],\r\n  })\r\n\r\n  graph.addEdge({\r\n    id: 'edge5',\r\n    shape: 'flow-edge',\r\n    source: node5,\r\n    target: node6,\r\n    labels: ['流程5'],\r\n  })\r\n\r\n  // 居中显示\r\n  graph.centerContent()\r\n\r\n  // ========== 添加交互：单击切换内置状态，双击切换到 error 状态 ==========\r\n\r\n  const builtinStates = ['default', 'hover', 'selected']\r\n  const stateMap = new Map<string, number>() // 记录每个节点的当前状态索引\r\n\r\n  // 双击事件：切换到 error 状态或恢复到 default 状态\r\n  graph.on('node:dblclick', ({ node }) => {\r\n    const currentState = node.getProp('_state') || 'default'\r\n\r\n    if (currentState === 'error') {\r\n      // 如果已经是 error，恢复到 default\r\n      designer.setNodeState(node, 'default')\r\n      stateMap.set(node.id, 0) // 重置索引\r\n      message.success('节点已恢复到默认状态')\r\n    } else {\r\n      // 切换到 error 状态\r\n      designer.setNodeState(node, 'error')\r\n      message.error('节点已设置为错误状态（双击可恢复）')\r\n    }\r\n  })\r\n\r\n  console.log('[Demo] 节点状态管理示例已加载（覆盖内置状态）')\r\n  message.success('已覆盖 3 种内置节点状态，单击切换状态，双击切换 error 状态')\r\n}\r\n</script>\r\n"