export default "﻿<template>\r\n  <div class=\"demo-permission-layout\">\r\n\r\n\r\n    <!-- 右侧流程设计器 -->\r\n    <div class=\"designer-container\">\r\n      <FlowDesignerLayout\r\n        class=\"flow-designer-test\"\r\n        ref=\"layoutRef\"\r\n        :mode=\"currentMode\"\r\n        :permission-config=\"permissionConfig\"\r\n        @ready=\"handleReady\"\r\n        @mode-change=\"handleModeChange\"\r\n      >\r\n        <!-- 顶部工具栏 -->\r\n        <template #toolbar=\"scope\">\r\n          <Toolbar\r\n            :zoom-percent=\"scope.zoomPercent\"\r\n            :has-selection=\"scope.hasSelection\"\r\n            :can-paste=\"scope.canPaste\"\r\n            :can-group=\"scope.canGroup\"\r\n            :can-ungroup=\"scope.canUngroup\"\r\n            :can-undo=\"scope.canUndo\"\r\n            :can-redo=\"scope.canRedo\"\r\n            :designer-mode=\"scope.currentMode\"\r\n            @undo=\"scope.onUndo\"\r\n            @redo=\"scope.onRedo\"\r\n            @zoom-in=\"scope.onZoomIn\"\r\n            @zoom-out=\"scope.onZoomOut\"\r\n            @zoom-to=\"scope.onZoomTo\"\r\n            @fit-view=\"scope.onFitView\"\r\n            @reset-view=\"scope.onResetView\"\r\n            @copy=\"scope.onCopy\"\r\n            @paste=\"scope.onPaste\"\r\n            @to-front=\"scope.onToFront\"\r\n            @to-back=\"scope.onToBack\"\r\n            @align-left=\"scope.onAlignLeft\"\r\n            @align-right=\"scope.onAlignRight\"\r\n            @align-top=\"scope.onAlignTop\"\r\n            @align-bottom=\"scope.onAlignBottom\"\r\n            @group=\"scope.onGroup\"\r\n            @ungroup=\"scope.onUngroup\"\r\n            @export=\"scope.onExport\"\r\n            @import=\"scope.onImport\"\r\n            @open-settings=\"scope.onOpenSettings\"\r\n            @mode-change=\"scope.onModeChange\"\r\n          />\r\n        </template>\r\n\r\n        <!-- 左侧节点面板 -->\r\n        <template #palette=\"scope\">\r\n          <NodePalette @start-drag=\"scope.onStartDrag\" />\r\n        </template>\r\n\r\n        <!-- 右侧属性面板 -->\r\n        <template #properties>\r\n          <PropertiesPanel />\r\n        </template>\r\n\r\n      </FlowDesignerLayout>\r\n\r\n      <!-- 模式选择器（固定在右上角） -->\r\n<!--      <ModeSelection-->\r\n<!--        :designer=\"designer\"-->\r\n<!--        @mode-change=\"handleModeChangeFromSelector\"-->\r\n<!--      />-->\r\n    </div>\r\n  </div>\r\n</template>\r\n\r\n<script setup lang=\"ts\">\r\nimport { ref, reactive, computed } from 'vue'\r\nimport { message } from 'ant-design-vue'\r\nimport { FlowDesignerLayout }  from '@quick-code/x6-flow-designer'\r\nimport type { FlowDesigner } from '@quick-code/x6-flow-designer'\r\nimport Toolbar from '@/views/Toolbar.vue'\r\nimport NodePalette from '@/views/NodePalette.vue'\r\nimport PropertiesPanel from '@/views/PropertiesPanel.vue'\r\nimport ModeSelection from '@/views/ModeSelection.vue'\r\n\r\nimport node30 from '/testfile/node-30.json'\r\n\r\n\r\nconst layoutRef = ref<InstanceType<typeof FlowDesignerLayout> | null>(null)\r\n// 测试用：搜索框插槽内的 input 引用（用于自动聚焦）\r\nconst searchInputRef = ref<HTMLInputElement | null>(null);\r\n\r\n// ─── Designer 实例（从 layoutRef 中提取，传递给 ModeSelection）──────────────\r\nconst designer = computed(() => layoutRef.value?.designer || null)\r\n\r\n// ─── 当前模式状态 ─────────────────────────────────────────────────────────────\r\nconst currentMode = ref('readonly')\r\n\r\n// ─── 权限配置（简化版：只配置需要覆盖默认值的权限）────────────────────────────\r\n/**\r\n * 用户权限配置\r\n *\r\n * 说明：\r\n * 1. 只需配置需要覆盖默认值的权限项\r\n * 2. 未配置的权限项会自动使用 defaultPermissionConfig.ts 中的默认值\r\n * 3. 扩展模式会自动继承 design 模式的配置\r\n * 4. Designer 类内部会自动合并默认配置\r\n *\r\n * 默认值规则：\r\n * - design 模式：所有权限默认开启（true）\r\n * - readonly 模式：禁用编辑权限，保留查看权限\r\n * - preview 模式：最小化界面，只保留基本查看\r\n */\r\nconst permissionConfig = reactive({\r\n  // ─── 设计模式 ───\r\n  design: {\r\n    // 不配置任何权限，则全部默认为true\r\n  },\r\n  readonly: {\r\n    showToolbar: false,\r\n    showNodePalette: false,\r\n    canAddNode: false,\r\n    canDrag: false,\r\n    canConnect: false,\r\n    canDelete: false,\r\n    canSelectEdge: false\r\n  }\r\n})\r\n\r\n\r\n// ─── ready 回调：拿到 designer 实例后加载本地数据 ─────────────────────────────\r\nfunction handleReady(designer: FlowDesigner) {\r\n  // ─── 加载测试数据 ──────────────────────────────────────────────────────\r\n  if (node30) {\r\n    try {\r\n      designer.load(node30)\r\n      //message.success('加载成功！')\r\n    } catch {\r\n      message.error('加载失败')\r\n    }\r\n  }\r\n}\r\n\r\n\r\n// ─── mode-change 事件 ─────────────────────────────────────────────────────────\r\nfunction handleModeChange(mode) {\r\n  message.success(`已切换至${{ design: '设计', readonly: '只读', preview: '预览' }[mode]}模式`)\r\n  currentMode.value = mode\r\n}\r\n\r\n// ─── 从 ModeSelection 组件触发的模式切换 ─────────────────────────────────────\r\nfunction handleModeChangeFromSelector(mode) {\r\n  // 🎯 调用 designer.setMode() 更新 designer 内部状态\r\n  if (designer.value) {\r\n    console.log('[FlowDesignerTest] 调用 designer.setMode()', mode)\r\n    designer.value.setMode(mode)\r\n  } else {\r\n    console.warn('[FlowDesignerTest] designer 实例不存在，无法切换模式')\r\n  }\r\n\r\n  // 更新本地状态（保持同步）\r\n  currentMode.value = mode\r\n\r\n  //message.success(`已切换至${{ design: '设计', readonly: '只读', preview: '预览' }[mode]}模式`)\r\n}\r\n\r\ndefineExpose({ layoutRef })\r\n</script>\r\n\r\n<style scoped>\r\n/* ==================== 布局容器 ==================== */\r\n.demo-permission-layout {\r\n  display: flex;\r\n  width: 100%;\r\n  height: 100%;\r\n  gap: 0;\r\n  background: #f5f5f5;\r\n}\r\n\r\n/* ==================== 左侧权限配置面板 ==================== */\r\n.permission-panel {\r\n  width: 180px;\r\n  background: #fff;\r\n  border-right: 1px solid #e8e8e8;\r\n  display: flex;\r\n  flex-direction: column;\r\n  overflow: hidden;\r\n}\r\n\r\n.permission-panel__header {\r\n  padding: 16px;\r\n  border-bottom: 1px solid #e8e8e8;\r\n  background: #fafafa;\r\n}\r\n\r\n.permission-panel__title {\r\n  font-size: 16px;\r\n  font-weight: 600;\r\n  color: #1a1a2e;\r\n  margin: 0 0 4px 0;\r\n}\r\n\r\n.permission-panel__mode {\r\n  display: inline-block;\r\n  padding: 2px 8px;\r\n  background: #e6f7ff;\r\n  color: #1677ff;\r\n  border-radius: 4px;\r\n  font-size: 12px;\r\n  font-weight: 500;\r\n}\r\n\r\n.permission-panel__content {\r\n  flex: 1;\r\n  overflow-y: auto;\r\n  padding: 16px;\r\n}\r\n\r\n/* ==================== 权限分组 ==================== */\r\n.permission-group {\r\n  margin-bottom: 20px;\r\n}\r\n\r\n.permission-group:last-child {\r\n  margin-bottom: 0;\r\n}\r\n\r\n.permission-group__title {\r\n  font-size: 14px;\r\n  font-weight: 600;\r\n  color: #333;\r\n  margin: 0 0 12px 0;\r\n  padding-bottom: 8px;\r\n  border-bottom: 2px solid #e8e8e8;\r\n}\r\n\r\n/* ==================== 权限列表 ==================== */\r\n.permission-list {\r\n  display: flex;\r\n  flex-direction: column;\r\n  gap: 8px;\r\n}\r\n\r\n.permission-item {\r\n  display: flex;\r\n  align-items: center;\r\n  gap: 8px;\r\n  padding: 6px 8px;\r\n  border-radius: 4px;\r\n  cursor: pointer;\r\n  transition: background 0.2s;\r\n  user-select: none;\r\n}\r\n\r\n.permission-item:hover {\r\n  background: #f5f5f5;\r\n}\r\n\r\n.permission-item__label {\r\n  font-size: 13px;\r\n  color: #555;\r\n  flex: 1;\r\n}\r\n\r\n/* ==================== 右侧设计器容器 ==================== */\r\n.designer-container {\r\n  flex: 1;\r\n  position: relative;\r\n  overflow: hidden;\r\n}\r\n\r\n.flow-designer-test {\r\n  width: 100%;\r\n  height: 100%;\r\n}\r\n\r\n/* ==================== 滚动条样式 ==================== */\r\n.permission-panel__content::-webkit-scrollbar {\r\n  width: 6px;\r\n}\r\n\r\n.permission-panel__content::-webkit-scrollbar-track {\r\n  background: #f1f1f1;\r\n}\r\n\r\n.permission-panel__content::-webkit-scrollbar-thumb {\r\n  background: #c1c1c1;\r\n  border-radius: 3px;\r\n}\r\n\r\n.permission-panel__content::-webkit-scrollbar-thumb:hover {\r\n  background: #a8a8a8;\r\n}\r\n\r\n/* ── 测试用自定义右键菜单样式 ────────────────────────────────────────────── */\r\n.custom-ctx-menu {\r\n  background: #fff;\r\n  border: 1px solid #e8e8e8;\r\n  border-radius: 6px;\r\n  box-shadow: 0 4px 16px rgba(0, 0, 0, 0.12);\r\n  padding: 4px 0;\r\n  min-width: 180px;\r\n  user-select: none;\r\n}\r\n\r\n.custom-ctx-menu__item {\r\n  padding: 7px 16px;\r\n  font-size: 13px;\r\n  color: #262626;\r\n  cursor: pointer;\r\n  transition: background 0.15s;\r\n  display: flex;\r\n  align-items: center;\r\n  gap: 8px;\r\n}\r\n\r\n.custom-ctx-menu__item:hover {\r\n  background: #f5f5f5;\r\n}\r\n\r\n.custom-ctx-menu__item--danger {\r\n  color: #f5222d;\r\n}\r\n\r\n.custom-ctx-menu__icon {\r\n  font-size: 14px;\r\n  flex-shrink: 0;\r\n}\r\n\r\n.custom-ctx-menu__divider {\r\n  height: 1px;\r\n  background: #f0f0f0;\r\n  margin: 4px 0;\r\n}\r\n\r\n/* ── 测试用自定义搜索框样式 ──────────────────────────────────────────────── */\r\n.custom-search-box {\r\n  position: absolute;\r\n  top: 3px;\r\n  right: 6px;\r\n  z-index: 1000;\r\n  display: flex;\r\n  align-items: center;\r\n  gap: 6px;\r\n  padding: 6px 10px;\r\n  background: #fff;\r\n  border-radius: 6px;\r\n  box-shadow: 0 2px 8px rgba(0, 0, 0, 0.15);\r\n  min-width: 280px;\r\n}\r\n\r\n.custom-search-box__icon {\r\n  color: #8c9bb5;\r\n  font-size: 14px;\r\n  flex-shrink: 0;\r\n}\r\n\r\n.custom-search-box__input {\r\n  flex: 1;\r\n  border: 1px solid #d9d9d9;\r\n  border-radius: 4px;\r\n  padding: 2px 8px;\r\n  font-size: 13px;\r\n  outline: none;\r\n  min-width: 140px;\r\n}\r\n\r\n.custom-search-box__input:focus {\r\n  border-color: #1890ff;\r\n  box-shadow: 0 0 0 2px rgba(24, 144, 255, 0.2);\r\n}\r\n\r\n.custom-search-box__count {\r\n  font-size: 12px;\r\n  color: #8c9bb5;\r\n  white-space: nowrap;\r\n  user-select: none;\r\n  min-width: 40px;\r\n  text-align: center;\r\n}\r\n\r\n.custom-search-box__btn {\r\n  border: 1px solid #d9d9d9;\r\n  background: #fff;\r\n  border-radius: 4px;\r\n  padding: 2px 8px;\r\n  cursor: pointer;\r\n  font-size: 12px;\r\n  line-height: 1.5;\r\n  transition: all 0.15s;\r\n}p\r\n\r\n.custom-search-box__btn:hover:not(:disabled) {\r\n  border-color: #1890ff;\r\n  color: #1890ff;\r\n}\r\n\r\n.custom-search-box__btn:disabled {\r\n  color: #bfbfbf;\r\n  cursor: not-allowed;\r\n}\r\n.my-node-tooltip {\r\n  background: #fff;\r\n  border: 1px solid #e8e8e8;\r\n  border-radius: 4px;\r\n  padding: 8px;\r\n  box-shadow: 0 2px 8px rgba(0, 0, 0, 0.15);\r\n}\r\n.my-edge-tooltip {\r\n  background: #fff;\r\n  border: 1px solid #e8e8e8;\r\n  border-radius: 4px;\r\n  padding: 8px;\r\n  box-shadow: 0 2px 8px rgba(0, 0, 0, 0.15);\r\n}\r\n.abc {\r\n  fill: red\r\n}\r\n\r\n/* 【测试】自定义连线标签 */\r\n.custom-edge-label {\r\n  display: inline-flex;\r\n  align-items: center;\r\n  gap: 4px;\r\n  padding: 2px 8px;\r\n  background: #fff;\r\n  border: 1px solid #cce3f9;\r\n  border-radius: 3px;\r\n  font-size: 12px;\r\n  color: #999999;\r\n  white-space: nowrap;\r\n  box-shadow: 0 1px 4px rgba(22, 119, 255, 0.2);\r\n  pointer-events: none;\r\n  font-weight: 500;\r\n  filter: drop-shadow(0 1px 2px rgba(0, 0, 0, 0.1));\r\n}\r\n.custom-edge-label-selected {\r\n  color: #1677ff;\r\n  border: 1px solid #1677ff;\r\n}\r\n\r\n.custom-edge-label__icon {\r\n  font-size: 11px;\r\n  flex-shrink: 0;\r\n}\r\n\r\n.custom-edge-label__text {\r\n  max-width: 80px;\r\n  overflow: hidden;\r\n  text-overflow: ellipsis;\r\n}\r\n</style>\r\n"