export default "<template>\r\n  <FlowDesignerLayout\r\n    @ready=\"handleReady\"\r\n  />\r\n</template>\r\n\r\n<script setup lang=\"ts\">\r\nimport { message } from 'ant-design-vue'\r\nimport { FlowDesignerLayout }  from '@quick-code/x6-flow-designer'\r\nimport type { FlowDesigner } from '@quick-code/x6-flow-designer'\r\nimport type { Edge } from '@antv/x6'\r\n\r\n/**\r\n * ready 回调：覆盖内置连线状态并初始化画布\r\n */\r\nfunction handleReady(designer: FlowDesigner) {\r\n  const graph = designer.getGraph()\r\n\r\n  // ========== 覆盖 5 种内置连线状态 ==========\r\n\r\n  // 1. 覆盖 default 状态：淡紫色虚线\r\n  designer.registerEdgeStateHandler('default', {\r\n    apply(edge) {\r\n      edge.setAttrs({\r\n        line: {\r\n          stroke: '#9333ea',\r\n          strokeWidth: 2,\r\n          //strokeDasharray: '4,4',\r\n        }\r\n      })\r\n      edge.setLabelAt(0, {\r\n        attrs: {\r\n          label: {\r\n            fill: '#6b21a8',\r\n            text: '自定义默认',\r\n          },\r\n          rect: {\r\n            fill: '#f3e8ff',\r\n            stroke: '#9333ea',\r\n            strokeWidth: 2,\r\n          }\r\n        }\r\n      })\r\n    }\r\n  })\r\n\r\n  // 2. 覆盖 hover 状态：橙色加粗 + 阴影效果\r\n  designer.registerEdgeStateHandler('hover', {\r\n    apply(edge) {\r\n      edge.setAttrs({\r\n        line: {\r\n          stroke: '#f97316',\r\n          strokeWidth: 4,\r\n          filter: {\r\n            name: 'dropShadow',\r\n            args: { dx: 0, dy: 2, blur: 4, color: 'rgba(249, 115, 22, 0.5)' }\r\n          }\r\n        }\r\n      })\r\n      edge.setLabelAt(0, {\r\n        attrs: {\r\n          label: {\r\n            fill: '#9a3412',\r\n            text: '悬停效果',\r\n            fontWeight: 'bold',\r\n          },\r\n          rect: {\r\n            fill: '#fed7aa',\r\n            stroke: '#f97316',\r\n            strokeWidth: 2,\r\n          }\r\n        }\r\n      })\r\n    },\r\n    cleanup(edge) {\r\n      edge.setAttrs({\r\n        line: {\r\n          filter: null\r\n        }\r\n      })\r\n    }\r\n  })\r\n\r\n  // 3. 覆盖 selected 状态：青色粗线 + 光晕\r\n  designer.registerEdgeStateHandler('selected', {\r\n    apply(edge) {\r\n      edge.setAttrs({\r\n        line: {\r\n          stroke: '#06b6d4',\r\n          strokeWidth: 3,\r\n        }\r\n      })\r\n      edge.setLabelAt(0, {\r\n        attrs: {\r\n          label: {\r\n            fill: '#164e63',\r\n            text: '已选中',\r\n            fontWeight: 'bold',\r\n            fontSize: 14,\r\n          },\r\n          rect: {\r\n            fill: '#cffafe',\r\n            stroke: '#06b6d4',\r\n            strokeWidth: 3,\r\n          }\r\n        }\r\n      })\r\n    },\r\n    cleanup(edge) {\r\n      edge.setAttrs({\r\n        line: {\r\n          filter: null\r\n        }\r\n      })\r\n    }\r\n  })\r\n\r\n  // 4. 覆盖 flowing 状态：粉色渐变 + CSS 流动动画\r\n  designer.registerEdgeStateHandler('flowing', {\r\n    apply(edge) {\r\n      edge.setAttrs({\r\n        line: {\r\n          stroke: '#ec4899',\r\n          strokeWidth: 3,\r\n          strokeDasharray: '10,5',\r\n          // ✅ 使用 CSS animation 替代 setInterval，避免定时器泄漏\r\n          style: {\r\n            animation: 'fd-flow 1s linear infinite'\r\n          }\r\n        }\r\n      })\r\n      edge.setLabelAt(0, {\r\n        attrs: {\r\n          label: {\r\n            fill: '#831843',\r\n            text: '数据流动中',\r\n            fontStyle: 'italic',\r\n          },\r\n          rect: {\r\n            fill: '#fce7f3',\r\n            stroke: '#ec4899',\r\n            strokeWidth: 2,\r\n          }\r\n        }\r\n      })\r\n    },\r\n    cleanup(edge) {\r\n      // 停止 CSS 动画\r\n      edge.setAttrs({\r\n        line: {\r\n          strokeDasharray: 0,\r\n          style: {\r\n            animation: 'none'\r\n          }\r\n        }\r\n      })\r\n    }\r\n  })\r\n\r\n  // 5. 覆盖 dimmed 状态：深灰色半透明 + 模糊\r\n  designer.registerEdgeStateHandler('dimmed', {\r\n    apply(edge) {\r\n      edge.setAttrs({\r\n        line: {\r\n          stroke: '#4b5563',\r\n          strokeWidth: 1,\r\n          opacity: 0.3,\r\n          filter: {\r\n            name: 'blur',\r\n            args: { stdDeviation: 1 }\r\n          }\r\n        }\r\n      })\r\n      edge.setLabelAt(0, {\r\n        attrs: {\r\n          label: {\r\n            fill: '#6b7280',\r\n            text: '已弱化',\r\n            fontStyle: 'italic',\r\n            fontSize: 11,\r\n          },\r\n          rect: {\r\n            fill: '#f3f4f6',\r\n            stroke: '#9ca3af',\r\n            strokeWidth: 1,\r\n            opacity: 0.5,\r\n          }\r\n        }\r\n      })\r\n    },\r\n    cleanup(edge) {\r\n      edge.setAttrs({\r\n        line: {\r\n          opacity: 1,\r\n          filter: null\r\n        }\r\n      })\r\n    }\r\n  })\r\n\r\n  // ========== 创建演示节点 ==========\r\n\r\n  const startNode = graph.addNode({\r\n    id: 'start',\r\n    shape: 'rect',\r\n    x: 80,\r\n    y: 120,\r\n    width: 100,\r\n    height: 60,\r\n    label: '开始',\r\n    attrs: {\r\n      body: {\r\n        stroke: '#5b8ff9',\r\n        strokeWidth: 2,\r\n        fill: '#e6f4ff',\r\n      },\r\n      label: {\r\n        fill: '#003a8c',\r\n        fontSize: 14,\r\n      },\r\n    },\r\n  })\r\n\r\n  const node1 = graph.addNode({\r\n    id: 'node1',\r\n    shape: 'rect',\r\n    x: 280,\r\n    y: 40,\r\n    width: 100,\r\n    height: 60,\r\n    label: '任务 A',\r\n    attrs: {\r\n      label: {\r\n        fontSize: 14,\r\n      },\r\n    },\r\n  })\r\n\r\n  const node2 = graph.addNode({\r\n    id: 'node2',\r\n    shape: 'rect',\r\n    x: 280,\r\n    y: 140,\r\n    width: 100,\r\n    height: 60,\r\n    label: '任务 B',\r\n    attrs: {\r\n      label: {\r\n        fontSize: 14,\r\n      },\r\n    },\r\n  })\r\n\r\n  const node3 = graph.addNode({\r\n    id: 'node3',\r\n    shape: 'rect',\r\n    x: 480,\r\n    y: 40,\r\n    width: 100,\r\n    height: 60,\r\n    label: '任务 C',\r\n    attrs: {\r\n      label: {\r\n        fontSize: 14,\r\n      },\r\n    },\r\n  })\r\n\r\n  const node4 = graph.addNode({\r\n    id: 'node4',\r\n    shape: 'rect',\r\n    x: 480,\r\n    y: 140,\r\n    width: 100,\r\n    height: 60,\r\n    label: '任务 D',\r\n    attrs: {\r\n      label: {\r\n        fontSize: 14,\r\n      },\r\n    },\r\n  })\r\n\r\n  const endNode = graph.addNode({\r\n    id: 'end',\r\n    shape: 'rect',\r\n    x: 680,\r\n    y: 120,\r\n    width: 100,\r\n    height: 60,\r\n    label: '结束',\r\n    attrs: {\r\n      body: {\r\n        stroke: '#5b8ff9',\r\n        strokeWidth: 2,\r\n        fill: '#e6f4ff',\r\n      },\r\n      label: {\r\n        fill: '#003a8c',\r\n        fontSize: 14,\r\n      },\r\n    },\r\n  })\r\n\r\n  // ========== 创建演示连线（展示 5 种覆盖的内置状态）==========\r\n\r\n  const edge1 = graph.addEdge({\r\n    id: 'edge1',\r\n    shape: 'flow-edge',\r\n    source: startNode,\r\n    target: node1,\r\n    labels: ['默认状态'],\r\n  })\r\n  designer.setEdgeState(edge1, 'default')\r\n\r\n  const edge2 = graph.addEdge({\r\n    id: 'edge2',\r\n    shape: 'flow-edge',\r\n    source: startNode,\r\n    target: node2,\r\n    labels: ['悬停状态'],\r\n  })\r\n  designer.setEdgeState(edge2, 'default')\r\n\r\n  const edge3 = graph.addEdge({\r\n    id: 'edge3',\r\n    shape: 'flow-edge',\r\n    source: node1,\r\n    target: node3,\r\n    labels: ['选中状态'],\r\n  })\r\n  designer.setEdgeState(edge3, 'default')\r\n\r\n  const edge4 = graph.addEdge({\r\n    id: 'edge4',\r\n    shape: 'flow-edge',\r\n    source: node2,\r\n    target: node4,\r\n    labels: ['流动状态'],\r\n  })\r\n  designer.setEdgeState(edge4, 'default')\r\n\r\n  const edge5 = graph.addEdge({\r\n    id: 'edge5',\r\n    shape: 'flow-edge',\r\n    source: node3,\r\n    target: endNode,\r\n    labels: ['弱化状态'],\r\n  })\r\n  designer.setEdgeState(edge5, 'default')\r\n\r\n  const edge6 = graph.addEdge({\r\n    id: 'edge6',\r\n    shape: 'flow-edge',\r\n    source: node4,\r\n    target: endNode,\r\n    labels: ['默认状态2'],\r\n  })\r\n  designer.setEdgeState(edge6, 'default')\r\n\r\n  // 居中显示\r\n  graph.centerContent()\r\n\r\n  // ========== 添加交互：点击连线切换状态 ==========\r\n\r\n  const states = ['default', 'hover', 'selected', 'flowing', 'dimmed']\r\n  const stateMap = new Map<string, number>() // 记录每条边的当前状态索引\r\n\r\n\r\n  console.log('[Demo] 连线状态管理示例已加载（覆盖内置状态）')\r\n  message.success('已覆盖 5 种内置连线状态，点击连线切换状态')\r\n}\r\n</script>\r\n"