}

.custom-palette__item-icon {
  width: 36px;
  height: 36px;
  display: flex;
  align-items: center;
  justify-content: center;
  border-radius: 6px;
  flex-shrink: 0;
}

.custom-palette__item-info {
  flex: 1;
  min-width: 0;
}

.custom-palette__item-label {
  font-size: 13px;
