  text-overflow: ellipsis;
}

/* ==================== 交互说明 ==================== */
.custom-palette__tips {
  margin-top: auto;
  padding: 12px;
  background: #fff9e6;
  border-top: 1px solid #ffe58f;
}

.tips-title {
  font-size: 12px;
  font-weight: 600;
  color: #d48806;
  margin-bottom: 8px;
}

.tips-list {
  margin: 0;
  padding-left: 16px;
  font-size: 11px;
  line-height: 1.8;
  color: #8c8c8c;
}

.tips-list li {
  margin-bottom: 4px;
}

.tips-list strong {
  color: #595959;
}

</style>


