export default "<template>\r\n  <div class=\"demo-slot-palette\">\r\n    <!-- 事件日志面板 -->\r\n    <div class=\"demo-slot-palette__log\">\r\n      <div class=\"demo-slot-palette__log-header\">\r\n        <h4>事件日志</h4>\r\n        <button class=\"demo-slot-palette__clear-btn\" @click=\"clearLogs\" title=\"清除日志\">\r\n          清除\r\n        </button>\r\n      </div>\r\n      <div class=\"demo-slot-palette__log-content\">\r\n        <div v-for=\"(log, index) in logs\" :key=\"index\" class=\"demo-slot-palette__log-item\">\r\n          {{ log }}\r\n        </div>\r\n      </div>\r\n    </div>\r\n\r\n    <!-- 画布容器 -->\r\n    <div class=\"demo-slot-palette__canvas\">\r\n      <FlowDesignerLayout\r\n        mode=\"design\"\r\n        :before-graph-init=\"handleBeforeGraphInit\"\r\n        @ready=\"handleReady\"\r\n        @selection-change=\"handleSelectionChange\"\r\n      >\r\n        <!-- 自定义节点面板插槽 -->\r\n        <template #palette=\"{ onStartDrag }\">\r\n          <div class=\"custom-palette\">\r\n            <div class=\"custom-palette__header\">\r\n              <h3 class=\"custom-palette__title\">自定义节点</h3>\r\n              <span class=\"custom-palette__desc\">拖拽到画布</span>\r\n            </div>\r\n\r\n            <div class=\"custom-palette__section\">\r\n              <div class=\"custom-palette__section-title\">基础节点</div>\r\n              <div\r\n                v-for=\"nodeType in customNodeTypes\"\r\n                :key=\"nodeType.type\"\r\n                class=\"custom-palette__item\"\r\n                @mousedown=\"(e) => handleStartDrag(e, nodeType, onStartDrag)\"\r\n              >\r\n                <div class=\"custom-palette__item-icon\" :style=\"{ background: nodeType.color }\">\r\n                  {{ nodeType.icon }}\r\n                </div>\r\n                <div class=\"custom-palette__item-info\">\r\n                  <div class=\"custom-palette__item-label\">{{ nodeType.label }}</div>\r\n                  <div class=\"custom-palette__item-hint\">{{ nodeType.hint }}</div>\r\n                </div>\r\n              </div>\r\n            </div>\r\n          </div>\r\n        </template>\r\n\r\n        <!-- node-type=\"custom-nodetype1\" 的节点内容 -->\r\n        <template #node-custom-nodetype1=\"{ node, graph, data, label, state }\">\r\n          <div class=\"cvn-task\" data-cvn-root :class=\"{ 'cvn-task--selected': node?.id == selectedNode?.id }\">\r\n            <div class=\"cvn-task__bar\" />\r\n            <div class=\"cvn-task__body\">\r\n              <!-- ✅ 新方式：使用响应式 label、data 和 state -->\r\n              <div class=\"cvn-task__title\">{{ label || '自定义vue插槽节点1' }}</div>\r\n              <div class=\"cvn-task__owner\">负责人：{{ data.owner || '未指定' }} state: {{ state }}</div>\r\n            </div>\r\n          </div>\r\n        </template>\r\n\r\n        <!-- node-type=\"custom-nodetype2\" 的节点内容 -->\r\n        <template #node-custom-nodetype2=\"{ node, graph, data, state }\">\r\n          <div class=\"cvn-notice\" data-cvn-root>\r\n            <div class=\"cvn-notice__icon\">🔔</div>\r\n            <div class=\"cvn-notice__body\">\r\n              <!-- ✅ 新方式：使用响应式 data 和 state -->\r\n              <div class=\"cvn-notice__title\">{{ data.label || '自定义vue插槽节点2' }}</div>\r\n              <div class=\"cvn-notice__desc\">通知类型节点 state: {{ state }}</div>\r\n            </div>\r\n          </div>\r\n        </template>\r\n      </FlowDesignerLayout>\r\n    </div>\r\n  </div>\r\n</template>\r\n\r\n<script setup lang=\"ts\">\r\nimport { ref } from 'vue'\r\nimport { FlowDesignerLayout }  from '@quick-code/x6-flow-designer'\r\nimport type { FlowDesigner, FlowDesignerOptions } from '@quick-code/x6-flow-designer'\r\nimport {Edge, Graph, Node} from '@antv/x6'\r\n\r\nconst selectedNode = ref<Node | null>(null)\r\nconst selectedEdge = ref<Edge | null>(null)\r\nconst selectionType = ref<'none' | 'node' | 'edge' | 'canvas'>('canvas')\r\n\r\nfunction handleSelectionChange(cells: any[]) {\r\n  if (cells.length === 0) {\r\n    // 未选中任何元素，显示画布配置\r\n    selectedNode.value = null\r\n    selectedEdge.value = null\r\n    selectionType.value = 'canvas'\r\n    addLog('📌 显示画布配置')\r\n  } else if (cells.length === 1) {\r\n    if (cells[0].isNode()) {\r\n      // 选中节点\r\n      selectedNode.value = cells[0] as Node\r\n      selectedEdge.value = null\r\n      selectionType.value = 'node'\r\n      addLog(`📌 选中节点: ${selectedNode.value.label || selectedNode.value.id}`)\r\n    } else if (cells[0].isEdge()) {\r\n      // 选中连线\r\n      selectedNode.value = null\r\n      selectedEdge.value = cells[0] as Edge\r\n      selectionType.value = 'edge'\r\n      addLog(`📌 选中连线: ${selectedEdge.value.id}`)\r\n    }\r\n  } else {\r\n    // 多选\r\n    selectedNode.value = null\r\n    selectedEdge.value = null\r\n    selectionType.value = 'none'\r\n    addLog(`📌 选中 ${cells.length} 个元素`)\r\n  }\r\n}\r\n\r\nconst logs = ref<string[]>([])\r\nconst customNodeTypes = ref([\r\n  {\r\n    type: 'custom-nodetype1',\r\n    label: '自定义任务',\r\n    icon: '📋',\r\n    hint: '用于任务处理',\r\n    color: '#fa8c16',\r\n    width: 160,\r\n    height: 80,\r\n    data: {\r\n      owner: '测试1',\r\n      detailPannelInfo: {\r\n        clazz:'123333'\r\n      }\r\n    }\r\n  },\r\n  {\r\n    type: 'custom-nodetype2',\r\n    label: '自定义通知',\r\n    icon: '🔔',\r\n    hint: '用于消息通知',\r\n    color: '#52c41a',\r\n    width: 140,\r\n    height: 70,\r\n    data: {\r\n      owner: '测试222'\r\n    }\r\n  },\r\n])\r\n\r\nfunction addLog(message: string) {\r\n  const timestamp = new Date().toLocaleTimeString()\r\n  logs.value.push(`[${timestamp}] ${message}`)\r\n}\r\n\r\nfunction clearLogs() {\r\n  logs.value = []\r\n}\r\n\r\n/**\r\n * Graph 初始化前钩子：注册自定义 X6 原生节点\r\n */\r\nfunction handleBeforeGraphInit(options: FlowDesignerOptions) {\r\n  addLog('🔧 beforeGraphInit: 开始注册自定义节点')\r\n\r\n\r\n}\r\n\r\nfunction handleReady(designer: FlowDesigner, graph: Graph) {\r\n\r\n  addLog('✅ 画布初始化完成')\r\n  addLog('🎨 自定义节点面板已渲染')\r\n  addLog('💡 提示: 点击左侧节点拖拽到画布')\r\n}\r\n\r\nfunction handleStartDrag(e: MouseEvent, nodeType: any, onStartDrag: any) {\r\n  addLog(`🎯 开始拖拽: ${nodeType.label}`)\r\n  console.log('nodeTypenodeTypenodeTypenodeTypenodeType::', nodeType);\r\n  // 使用 palette 插槽提供的 onStartDrag 函数\r\n  // 参数：(event, nodeConfig)\r\n  // nodeConfig 是 X6 Node 的配置对象，包含所有节点属性\r\n  onStartDrag(e, {\r\n    shape: 'common-vue-node',   // X6 节点类型\r\n    label: nodeType.label,      // 节点标签（顶级属性）\r\n    width: nodeType.width,      // 节点宽度（顶级属性）\r\n    height: nodeType.height,    // 节点高度（顶级属性）\r\n    'node-type': nodeType.type,\r\n    data: {\r\n      nodeType: nodeType.type,  // Vue 插槽名称，对应 <template #node-xxx>\r\n      ...nodeType.data,         // 展开所有业务数据（owner 等）\r\n    }\r\n  })\r\n}\r\n</script>\r\n\r\n<style scoped>\r\n.demo-slot-palette {\r\n  display: flex;\r\n  height: 100%;\r\n  min-height: 500px;\r\n  gap: 16px;\r\n}\r\n\r\n.demo-slot-palette__log {\r\n  width: 280px;\r\n  border: 1px solid #e8e8e8;\r\n  border-radius: 8px;\r\n  padding: 16px;\r\n  background: #fafafa;\r\n  overflow: hidden;\r\n  display: flex;\r\n  flex-direction: column;\r\n}\r\n\r\n.demo-slot-palette__log-header {\r\n  display: flex;\r\n  justify-content: space-between;\r\n  align-items: center;\r\n  margin-bottom: 12px;\r\n}\r\n\r\n.demo-slot-palette__log h4 {\r\n  margin: 0;\r\n  font-size: 14px;\r\n  color: #1a1a2e;\r\n  font-weight: 600;\r\n}\r\n\r\n.demo-slot-palette__clear-btn {\r\n  padding: 2px 8px;\r\n  font-size: 12px;\r\n  color: #666;\r\n  background: #fff;\r\n  border: 1px solid #d9d9d9;\r\n  border-radius: 4px;\r\n  cursor: pointer;\r\n  transition: all 0.2s;\r\n  user-select: none;\r\n}\r\n\r\n.demo-slot-palette__clear-btn:hover {\r\n  color: #1890ff;\r\n  border-color: #1890ff;\r\n}\r\n\r\n.demo-slot-palette__log-content {\r\n  flex: 1;\r\n  overflow-y: auto;\r\n  font-size: 12px;\r\n  line-height: 1.8;\r\n}\r\n\r\n.demo-slot-palette__log-item {\r\n  padding: 4px 0;\r\n  color: #555;\r\n  font-family: 'Monaco', 'Menlo', 'Consolas', monospace;\r\n  border-bottom: 1px solid #f0f0f0;\r\n}\r\n\r\n.demo-slot-palette__log-item:last-child {\r\n  border-bottom: none;\r\n}\r\n\r\n.demo-slot-palette__canvas {\r\n  flex: 1;\r\n  border: 1px solid #e8e8e8;\r\n  border-radius: 8px;\r\n  overflow: hidden;\r\n  background: #fff;\r\n}\r\n\r\n/* ==================== 自定义节点面板样式 ==================== */\r\n.custom-palette {\r\n  display: flex;\r\n  flex-direction: column;\r\n  height: 100%;\r\n  background: linear-gradient(to bottom, #f9fafb, #ffffff);\r\n  border-right: 1px solid #e8e8e8;\r\n  width: 180px;\r\n}\r\n\r\n.custom-palette__header {\r\n  padding: 16px;\r\n  border-bottom: 2px solid #e8e8e8;\r\n  background: #fff;\r\n}\r\n\r\n.custom-palette__title {\r\n  margin: 0 0 4px 0;\r\n  font-size: 16px;\r\n  font-weight: 600;\r\n  color: #1a1a2e;\r\n}\r\n\r\n.custom-palette__desc {\r\n  font-size: 12px;\r\n  color: #999;\r\n}\r\n\r\n.custom-palette__section {\r\n  padding: 12px;\r\n}\r\n\r\n.custom-palette__section-title {\r\n  font-size: 11px;\r\n  font-weight: 600;\r\n  color: #999;\r\n  text-transform: uppercase;\r\n  letter-spacing: 0.06em;\r\n  margin-bottom: 8px;\r\n  padding: 0 4px;\r\n}\r\n\r\n.custom-palette__item {\r\n  display: flex;\r\n  align-items: center;\r\n  gap: 12px;\r\n  padding: 10px;\r\n  margin-bottom: 8px;\r\n  background: #fff;\r\n  border: 1px solid #e8e8e8;\r\n  border-radius: 6px;\r\n  cursor: move;\r\n  transition: all 0.2s;\r\n  user-select: none;\r\n}\r\n\r\n.custom-palette__item:hover {\r\n  border-color: #1677ff;\r\n  box-shadow: 0 2px 8px rgba(22, 119, 255, 0.15);\r\n  transform: translateY(-1px);\r\n}\r\n\r\n.custom-palette__item:active {\r\n  transform: translateY(0);\r\n  box-shadow: 0 1px 4px rgba(22, 119, 255, 0.2);\r\n}\r\n\r\n.custom-palette__item-icon {\r\n  width: 36px;\r\n  height: 36px;\r\n  display: flex;\r\n  align-items: center;\r\n  justify-content: center;\r\n  border-radius: 6px;\r\n  font-size: 18px;\r\n  flex-shrink: 0;\r\n}\r\n\r\n.custom-palette__item-info {\r\n  flex: 1;\r\n  min-width: 0;\r\n}\r\n\r\n.custom-palette__item-label {\r\n  font-size: 13px;\r\n  font-weight: 500;\r\n  color: #333;\r\n  margin-bottom: 2px;\r\n}\r\n\r\n.custom-palette__item-hint {\r\n  font-size: 11px;\r\n  color: #999;\r\n  white-space: nowrap;\r\n  overflow: hidden;\r\n  text-overflow: ellipsis;\r\n}\r\n\r\n/* ==================== 自定义节点样式 ==================== */\r\n/* 任务节点样式 */\r\n.cvn-task {\r\n  display: flex;\r\n  flex-direction: column;\r\n  min-width: 260px;\r\n  background: #fff;\r\n  border: 1.5px solid #e8e8e8;\r\n  border-radius: 8px;\r\n  overflow: hidden;\r\n  box-shadow: 0 2px 8px rgba(0, 0, 0, 0.08);\r\n  user-select: none;\r\n  transition: border-color 0.2s, box-shadow 0.2s;\r\n}\r\n\r\n.cvn-task:hover {\r\n  border-color: #ffa940;\r\n}\r\n\r\n.cvn-task--selected {\r\n  border: 3px solid #fa8c16;\r\n  box-shadow: 0 0 0 3px rgba(250, 140, 22, 0.15);\r\n}\r\n\r\n.cvn-task__bar {\r\n  height: 4px;\r\n  flex-shrink: 0;\r\n  background: linear-gradient(90deg, #fa8c16 0%, #ffc069 100%);\r\n}\r\n\r\n.cvn-task__body {\r\n  padding: 10px 14px;\r\n}\r\n\r\n.cvn-task__title {\r\n  font-size: 13px;\r\n  font-weight: 600;\r\n  color: #262626;\r\n}\r\n\r\n.cvn-task__owner {\r\n  font-size: 11px;\r\n  color: #8c8c8c;\r\n  margin-top: 4px;\r\n}\r\n\r\n/* 通知节点样式 */\r\n.cvn-notice {\r\n  display: flex;\r\n  align-items: center;\r\n  gap: 10px;\r\n  min-width: 140px;\r\n  padding: 10px 14px;\r\n  background: #fff;\r\n  border: 1.5px solid #e8e8e8;\r\n  border-radius: 8px;\r\n  box-shadow: 0 2px 8px rgba(0, 0, 0, 0.08);\r\n  user-select: none;\r\n  transition: border-color 0.2s, box-shadow 0.2s;\r\n}\r\n\r\n.cvn-notice:hover {\r\n  border-color: #73d13d;\r\n}\r\n\r\n.cvn-notice--selected {\r\n  border: 2px solid #52c41a;\r\n  box-shadow: 0 0 0 3px rgba(82, 196, 26, 0.15);\r\n}\r\n\r\n.cvn-notice__icon {\r\n  font-size: 24px;\r\n  flex-shrink: 0;\r\n}\r\n\r\n.cvn-notice__body {\r\n  flex: 1;\r\n  min-width: 0;\r\n}\r\n\r\n.cvn-notice__title {\r\n  font-size: 13px;\r\n  font-weight: 600;\r\n  color: #262626;\r\n  margin-bottom: 2px;\r\n}\r\n\r\n.cvn-notice__desc {\r\n  font-size: 11px;\r\n  color: #8c8c8c;\r\n}\r\n</style>\r\n"