export default "﻿<template>\r\n  <div class=\"demo-selection\">\r\n    <!-- 事件日志面板 -->\r\n    <div class=\"demo-selection__log\">\r\n      <div class=\"demo-selection__log-header\">\r\n        <h4>事件日志</h4>\r\n        <button class=\"demo-selection__clear-btn\" @click=\"clearLogs\" title=\"清除日志\">\r\n          清除\r\n        </button>\r\n      </div>\r\n      <div class=\"demo-selection__log-content\">\r\n        <div v-for=\"(log, index) in logs\" :key=\"index\" class=\"demo-selection__log-item\">\r\n          {{ log }}\r\n        </div>\r\n      </div>\r\n    </div>\r\n\r\n    <!-- 画布容器 -->\r\n    <div class=\"demo-selection__canvas\">\r\n      <div class=\"demo-selection__tip\">\r\n        💡 点击或框选节点，观察选区变化事件\r\n      </div>\r\n      <FlowDesignerLayout @selection-change=\"handleSelectionChange\" @ready=\"handleReady\" />\r\n    </div>\r\n  </div>\r\n</template>\r\n\r\n<script setup lang=\"ts\">\r\nimport { ref } from 'vue'\r\nimport { FlowDesignerLayout }  from '@quick-code/x6-flow-designer'\r\nimport type { FlowDesigner } from '@quick-code/x6-flow-designer'\r\nimport type { Graph } from '@antv/x6'\r\n\r\nconst logs = ref<string[]>([])\r\n\r\nfunction addLog(message: string) {\r\n  const timestamp = new Date().toLocaleTimeString()\r\n  logs.value.push(`[${timestamp}] ${message}`)\r\n}\r\n\r\nfunction clearLogs() {\r\n  logs.value = []\r\n}\r\n\r\nfunction handleReady(designer, graph) {\r\n  addLog('✅ 画布初始化完成')\r\n\r\n  // 添加多个节点供选择\r\n  const node1 = graph.addNode({\r\n    id: 'node1',\r\n    shape: 'rect',\r\n    x: 100,\r\n    y: 80,\r\n    width: 100,\r\n    height: 60,\r\n    label: '节点1',\r\n    attrs: {\r\n      body: { fill: '#5F95FF', stroke: '#2563EB' },\r\n      label: { fill: '#fff' },\r\n    },\r\n  })\r\n\r\n  const node2 = graph.addNode({\r\n    id: 'node2',\r\n    shape: 'rect',\r\n    x: 250,\r\n    y: 80,\r\n    width: 100,\r\n    height: 60,\r\n    label: '节点2',\r\n    attrs: {\r\n      body: { fill: '#10B981', stroke: '#059669' },\r\n      label: { fill: '#fff' },\r\n    },\r\n  })\r\n\r\n  const node3 = graph.addNode({\r\n    id: 'node3',\r\n    shape: 'rect',\r\n    x: 100,\r\n    y: 180,\r\n    width: 100,\r\n    height: 60,\r\n    label: '节点3',\r\n    attrs: {\r\n      body: { fill: '#F59E0B', stroke: '#D97706' },\r\n      label: { fill: '#fff' },\r\n    },\r\n  })\r\n\r\n  const node4 = graph.addNode({\r\n    id: 'node4',\r\n    shape: 'rect',\r\n    x: 250,\r\n    y: 180,\r\n    width: 100,\r\n    height: 60,\r\n    label: '节点4',\r\n    attrs: {\r\n      body: { fill: '#EF4444', stroke: '#DC2626' },\r\n      label: { fill: '#fff' },\r\n    },\r\n  })\r\n\r\n  // 添加连线\r\n  graph.addEdge({\r\n    shape: 'flow-edge',\r\n    source: node1,\r\n    target: node2,\r\n    labels: ['连线1'],\r\n  })\r\n\r\n  graph.addEdge({\r\n    shape: 'flow-edge',\r\n    source: node3,\r\n    target: node4,\r\n    labels: ['连线2'],\r\n  })\r\n\r\n  addLog('📦 已添加 4 个节点和 2 条连线')\r\n  graph.centerContent()\r\n}\r\n\r\n/**\r\n * @selection-change 事件处理函数\r\n * 参数：cells - 当前选中的单元格数组\r\n */\r\nfunction handleSelectionChange(cells: Array<{ id: string; isNode: () => boolean }>) {\r\n  addLog(`🔄 @selection-change 事件触发`)\r\n  addLog(`📊 选中数量: ${cells.length}`)\r\n\r\n  if (cells.length === 0) {\r\n    addLog('❌ 已清空选区')\r\n  } else {\r\n    cells.forEach((cell, index) => {\r\n      const type = cell.isNode() ? '节点' : '连线'\r\n      addLog(`  ${index + 1}. ${type} ID: ${cell.id}`)\r\n    })\r\n  }\r\n}\r\n</script>\r\n\r\n<style scoped>\r\n.demo-selection {\r\n  display: flex;\r\n  height: 100%; /* 修改：从固定高度改为 100%，支持全屏 */\r\n  min-height: 400px; /* 添加：最小高度，非全屏时保持合理尺寸 */\r\n  gap: 16px;\r\n}\r\n\r\n.demo-selection__log {\r\n  width: 300px;\r\n  border: 1px solid #e8e8e8;\r\n  border-radius: 8px;\r\n  padding: 16px;\r\n  background: #fafafa;\r\n  overflow: hidden;\r\n  display: flex;\r\n  flex-direction: column;\r\n}\r\n\r\n.demo-selection__log-header {\r\n  display: flex;\r\n  justify-content: space-between;\r\n  align-items: center;\r\n  margin-bottom: 12px;\r\n}\r\n\r\n.demo-selection__log h4 {\r\n  margin: 0;\r\n  font-size: 14px;\r\n  color: #1a1a2e;\r\n  font-weight: 600;\r\n}\r\n\r\n.demo-selection__clear-btn {\r\n  padding: 2px 8px;\r\n  font-size: 12px;\r\n  color: #666;\r\n  background: #fff;\r\n  border: 1px solid #d9d9d9;\r\n  border-radius: 4px;\r\n  cursor: pointer;\r\n  transition: all 0.2s;\r\n  user-select: none;\r\n}\r\n\r\n.demo-selection__clear-btn:hover {\r\n  color: #1890ff;\r\n  border-color: #1890ff;\r\n}\r\n\r\n.demo-selection__log-content {\r\n  flex: 1;\r\n  overflow-y: auto;\r\n  font-size: 12px;\r\n  line-height: 1.8;\r\n}\r\n\r\n.demo-selection__log-item {\r\n  padding: 4px 0;\r\n  color: #555;\r\n  font-family: 'Monaco', 'Menlo', 'Consolas', monospace;\r\n  border-bottom: 1px solid #f0f0f0;\r\n}\r\n\r\n.demo-selection__log-item:last-child {\r\n  border-bottom: none;\r\n}\r\n\r\n.demo-selection__canvas {\r\n  flex: 1;\r\n  border: 1px solid #e8e8e8;\r\n  border-radius: 8px;\r\n  overflow: hidden;\r\n  background: #fff;\r\n  display: flex;\r\n  flex-direction: column;\r\n}\r\n\r\n.demo-selection__tip {\r\n  padding: 10px 16px;\r\n  background: #e6f7ff;\r\n  border-bottom: 1px solid #91d5ff;\r\n  font-size: 13px;\r\n  color: #0050b3;\r\n}\r\n</style>\r\n"