<template>
  <div style="width: 100%;height: 100%">
    <div class="node-start" :class="{ 'node-start--selected': isSelected }">
      <div class="body">
        <img v-if="!isSelected" :src="startSvg" />
        <img v-if="isSelected" :src="startSvgHover" />
        <div class="info">
          <div class="name">{{ label || '开始' }}</div>
        </div>
      </div>
    </div>
  </div>
</template>

<script setup lang="ts">
import { ref, onMounted, onUnmounted, inject } from 'vue'
import type { Node, Graph } from '@antv/x6'
import type { FlowNodeData } from '../types/flow.types'
import startSvg from '../icons/start.svg';
import startSvgHover from '../icons/start-hover.svg';

const props     = defineProps<{ node: Node }>()
const getGraph  = inject<() => Graph>('getGraph')

const nodeData   = ref<FlowNodeData>(props.node.getData() ?? {})
const isSelected = ref(false)
const label = ref('')

const updateNodeData = () => {
  nodeData.value = props.node.getData() ?? {}

  label.value = props.node.getProp('label');
}

onMounted(() => {
  props.node.on('change:data', updateNodeData)
  const graph = getGraph?.()
  if (graph) {
    graph.on('cell:selected',   ({ cell }) => { if (cell.id === props.node.id) isSelected.value = true  })
    graph.on('cell:unselected', ({ cell }) => { if (cell.id === props.node.id) isSelected.value = false })
  }
})

onUnmounted(() => {
  props.node.off('change:data', updateNodeData)
})
</script>

<style scoped>
.node-start {
  width: 100%;
  height: 100%;
  background: #fff;
  border: 1px solid #52c41a;
  border-radius: 8px; overflow: hidden;
  box-shadow: 0 2px 8px rgba(0,0,0,.08);
  display: flex; flex-direction: column;
  user-select: none;
  background: #edf8e7;
  transition: box-shadow 0.2s, border-color 0.2s;
}
.node-start:hover {
  border: 2px solid #52c41a;
  -background: #f1f5f1;
}
.node-start--selected {
  border: 2px solid #52c41a;
  background: #8fd16f;
  box-shadow: 0 0 0 3px rgba(245,34,45,0.15), 0 2px 8px rgba(0,0,0,.08);
}
.node-start--selected .name{
  color: white;
}
.body { flex: 1; display: flex; align-items: center; padding: 0 12px; gap: 10px; }
.icon { font-size: 16px; color: #52c41a; }
.info { overflow: hidden; flex: 1; }
.name { font-size: 13px; color: #81cb5c; white-space: nowrap; overflow: hidden; text-overflow: ellipsis; font-weight: 390}
</style>
