<template>
  <div class="toolbar">

    <!-- 中：操作按钮组 -->
    <div class="toolbar__left">
      <a-space :size="4" align="center">
        <a-tooltip title="导入 JSON">
          <a-button size="small" :disabled="!capabilities.canImport" @click="() => fileInputRef?.click()">
            <template #icon><ImportOutlined /></template>
          </a-button>
        </a-tooltip>
        <a-tooltip title="导出 JSON">
          <a-button size="small" :disabled="!capabilities.canExport" @click="emit('export')">
            <template #icon><ExportOutlined /></template>
          </a-button>
        </a-tooltip>

        <a-divider type="vertical" style="margin: 0 2px" />

        <!-- 撤销/重做 -->
        <a-tooltip title="撤销 (Ctrl+Z)">
          <a-button size="small" :disabled="!capabilities.canUndo || !canUndo" @click="emit('undo')">
            <template #icon><UndoOutlined /></template>
          </a-button>
        </a-tooltip>
        <a-tooltip title="重做 (Ctrl+Y)">
          <a-button size="small" :disabled="!capabilities.canRedo || !canRedo" @click="emit('redo')">
            <template #icon><RedoOutlined /></template>
          </a-button>
        </a-tooltip>

        <a-divider type="vertical" style="margin: 0 2px" />

        <!-- ✅ 缩放操作组 -->
        <a-tooltip title="缩小 (Ctrl+-)">
          <a-button size="small" :disabled="zoomPercent <= 20" @click="emit('zoomOut')">
            <template #icon><ZoomOutOutlined /></template>
          </a-button>
        </a-tooltip>

                        <a-select
          :value="zoomPercent"
          size="small"
          style="width: 76px"
          @change="(v: number) => emit('zoomTo', v)"
        >
          <a-select-option :value="25">25%</a-select-option>
          <a-select-option :value="50">50%</a-select-option>
          <a-select-option :value="75">75%</a-select-option>
          <a-select-option :value="100">100%</a-select-option>
          <a-select-option :value="125">125%</a-select-option>
          <a-select-option :value="150">150%</a-select-option>
          <a-select-option :value="200">200%</a-select-option>
        </a-select>


        <a-tooltip title="放大 (Ctrl+=)">
          <a-button size="small" :disabled="zoomPercent >= 500" @click="emit('zoomIn')">
            <template #icon><ZoomInOutlined /></template>
          </a-button>
        </a-tooltip>
        <a-tooltip title="适应窗口 (Ctrl+0)">
          <a-button size="small" :disabled="!capabilities.canFitView" @click="emit('fitView')">
            <template #icon><CompressOutlined /></template>
          </a-button>
        </a-tooltip>
        <a-tooltip title="重置视图 (Ctrl+Shift+H)">
          <a-button size="small" :disabled="!capabilities.canResetView" @click="emit('resetView')">
            <template #icon><FullscreenExitOutlined /></template>
          </a-button>
        </a-tooltip>

        <a-divider type="vertical" style="margin: 0 2px" />

        <!-- 层级调整 -->
        <a-tooltip title="层级前置">
          <a-button size="small" :disabled="!capabilities.canToFront || !hasSelection" @click="emit('toFront')">
            <template #icon><VerticalAlignTopOutlined /></template>
          </a-button>
        </a-tooltip>
        <a-tooltip title="层级后置">
          <a-button size="small" :disabled="!capabilities.canToBack || !hasSelection" @click="emit('toBack')">
            <template #icon><VerticalAlignBottomOutlined /></template>
          </a-button>
        </a-tooltip>

        <a-divider type="vertical" style="margin: 0 2px" />

                <!-- ✅ 对齐按钮组 -->
        <a-tooltip title="左对齐 (Ctrl+Shift+L)">
          <a-button
            size="small"
            :disabled="!capabilities.canAlign || !capabilities.canAlignLeft || !canGroup"
            @click="emit('align-left')"
          >
            <template #icon><AlignLeftOutlined /></template>
          </a-button>
        </a-tooltip>

        <a-tooltip title="右对齐 (Ctrl+Shift+R)">
          <a-button
            size="small"
            :disabled="!capabilities.canAlign || !capabilities.canAlignRight || !canGroup"
            @click="emit('align-right')"
          >
            <template #icon><AlignRightOutlined /></template>
          </a-button>
        </a-tooltip>

        <a-tooltip title="上对齐 (Ctrl+Shift+T)">
          <a-button
            size="small"
            :disabled="!capabilities.canAlign || !capabilities.canAlignTop || !canGroup"
            @click="emit('align-top')"
          >
            <template #icon><BorderTopOutlined /></template>
          </a-button>
        </a-tooltip>

        <a-tooltip title="下对齐 (Ctrl+Shift+B)">
          <a-button
            size="small"
            :disabled="!capabilities.canAlign || !capabilities.canAlignBottom || !canGroup"
            @click="emit('align-bottom')"
          >
            <template #icon><BorderBottomOutlined /></template>
          </a-button>
        </a-tooltip>

        <a-divider type="vertical" style="margin: 0 2px" />

        <!-- 复制/粘贴 -->
        <a-tooltip title="复制选中节点 (Ctrl+C)">
          <a-button size="small" :disabled="!capabilities.canCopy || !hasSelection" @click="emit('copy')">
            <template #icon><CopyOutlined /></template>
            复制
          </a-button>
        </a-tooltip>
        <a-tooltip title="粘贴节点 (Ctrl+V)">
          <a-button size="small" :disabled="!capabilities.canPaste || !canPaste" @click="emit('paste')">
            <template #icon><SnippetsOutlined /></template>
            粘贴
          </a-button>
        </a-tooltip>

        <a-divider type="vertical" style="margin: 0 2px" />

        <!-- 成组/解组 -->
        <a-tooltip title="成组 (Ctrl+G)">
          <a-button size="small" :disabled="!capabilities.canGroup || !canGroup" @click="emit('group')">
            <template #icon><GroupOutlined /></template>
            成组
          </a-button>
        </a-tooltip>
        <a-tooltip title="解组 (Ctrl+Shift+G)">
          <a-button size="small" :disabled="!capabilities.canGroup || !canUngroup" @click="emit('ungroup')">
            <template #icon><UngroupOutlined /></template>
            解组
          </a-button>
        </a-tooltip>
      </a-space>
    </div>

    <!-- 隐藏文件 input -->
    <input
      ref="fileInputRef"
      type="file"
      accept=".json"
      style="display: none"
      @change="handleFileChange"
    />
  </div>
</template>

<script setup lang="ts">
import { ref, inject, computed, type ComputedRef } from 'vue'
import { Modal } from 'ant-design-vue'
import type { DesignerMode } from './types/flow.types'
import {
  FileTextOutlined, FileAddOutlined, SaveOutlined,
  ImportOutlined, ExportOutlined,
  UndoOutlined, RedoOutlined,
  ZoomInOutlined, ZoomOutOutlined,
  CompressOutlined, FullscreenExitOutlined,
    CopyOutlined, SnippetsOutlined,
  VerticalAlignTopOutlined, VerticalAlignBottomOutlined,
  AlignLeftOutlined, AlignRightOutlined,
  BorderTopOutlined, BorderBottomOutlined,
  GroupOutlined, UngroupOutlined,
  RocketOutlined,
  SettingOutlined,
} from '@ant-design/icons-vue'
import type { ModeCapabilities } from './types/flow.types'

const props = defineProps<{
  zoomPercent: number
  hasSelection: boolean
  canPaste: boolean
  canGroup: boolean
  canUngroup: boolean
    canUndo?: boolean
  canRedo?: boolean
  designerMode?: DesignerMode
}>()

// ── 注入权限 ──────────────────────────────────────────────────────────────────
const capabilities = inject<ComputedRef<ModeCapabilities>>('capabilities')!

const emit = defineEmits<{
  (e: 'undo'): void
  (e: 'redo'): void
  (e: 'zoomIn'): void
  (e: 'zoomOut'): void
  (e: 'zoomTo', percent: number): void
  (e: 'fitView'): void
  (e: 'resetView'): void
    (e: 'copy'): void
  (e: 'paste'): void
  (e: 'toFront'): void
  (e: 'toBack'): void
  (e: 'align-left'): void
  (e: 'align-right'): void
  (e: 'align-top'): void
  (e: 'align-bottom'): void
  (e: 'group'): void
  (e: 'ungroup'): void
  (e: 'export'): void
  (e: 'import', file: File): void
  (e: 'publish'): void
  (e: 'new'): void
  (e: 'save'): void
    (e: 'openSettings'): void
  (e: 'modeChange', mode: DesignerMode): void
}>()


const fileInputRef = ref<HTMLInputElement | null>(null)

function handleSave() { emit('save') }

function handleFileChange(e: Event) {
  const file = (e.target as HTMLInputElement).files?.[0]
  if (file) {
    emit('import', file)
    ;(e.target as HTMLInputElement).value = ''
  }
}
</script>

<style scoped>
.toolbar {
  display: flex; align-items: center;
  justify-content: space-between;
  height: 52px; padding: 0 16px;
  background: #fff;
  border-bottom: 1px solid #f0f0f0;
  box-shadow: 0 1px 4px rgba(0,0,0,.06);
  flex-shrink: 0;
  max-width: 100%;
  overflow: auto;
}
.toolbar__left  { display: flex; align-items: center; flex-shrink: 0; }
.toolbar__center{ flex: 1; display: flex; justify-content: center; }
.toolbar__right { flex-shrink: 0; }
</style>

