export default "<template>\r\n  <div class=\"demo-performance\">\r\n    <!-- 配置面板 -->\r\n    <div class=\"demo-performance__panel\">\r\n      <div class=\"demo-performance__panel-header\">\r\n        <h4>性能测试配置</h4>\r\n      </div>\r\n      <div class=\"demo-performance__panel-content\">\r\n        <!-- 节点数量配置 -->\r\n        <div class=\"demo-performance__config-item\">\r\n          <label class=\"demo-performance__label\">节点数量</label>\r\n          <div class=\"demo-performance__input-group\">\r\n            <input\r\n              type=\"number\"\r\n              v-model.number=\"nodeCount\"\r\n              :min=\"10\"\r\n              :max=\"2000\"\r\n              class=\"demo-performance__input\"\r\n            />\r\n            <button\r\n              class=\"demo-performance__btn demo-performance__btn--primary\"\r\n              @click=\"generateNodes\"\r\n              :disabled=\"isGenerating\"\r\n            >\r\n              {{ isGenerating ? '生成中...' : '重新生成' }}\r\n            </button>\r\n          </div>\r\n          <div class=\"demo-performance__hint\">\r\n            建议范围：10-2000 个节点\r\n          </div>\r\n        </div>\r\n\r\n        <!-- 布局方式 -->\r\n        <div class=\"demo-performance__config-item\">\r\n          <label class=\"demo-performance__label\">布局方式</label>\r\n          <select v-model=\"layoutType\" class=\"demo-performance__select\">\r\n            <option value=\"grid\">网格布局</option>\r\n            <option value=\"circular\">环形布局</option>\r\n            <option value=\"random\">随机布局</option>\r\n          </select>\r\n        </div>\r\n\r\n        <!-- 节点类型选择 -->\r\n        <div class=\"demo-performance__config-item\">\r\n          <label class=\"demo-performance__label\">节点类型</label>\r\n          <select v-model=\"nodeType\" class=\"demo-performance__select\">\r\n            <option value=\"rect\">矩形节点 (rect)</option>\r\n            <option value=\"circle\">圆形节点 (circle)</option>\r\n            <option value=\"common-vue-node\">Vue 插槽节点</option>\r\n            <option value=\"vue-node-1\">Vue 注册节点 🚀</option>\r\n          </select>\r\n        </div>\r\n\r\n        <!-- 连线配置 -->\r\n        <div class=\"demo-performance__config-item\">\r\n          <label class=\"demo-performance__checkbox\">\r\n            <input type=\"checkbox\" v-model=\"showEdges\" @change=\"toggleEdges\" />\r\n            显示连线\r\n          </label>\r\n        </div>\r\n\r\n        <!-- 连线标签配置 -->\r\n        <div class=\"demo-performance__config-item\">\r\n          <label class=\"demo-performance__checkbox\">\r\n            <input type=\"checkbox\" v-model=\"showEdgeLabels\" :disabled=\"!showEdges\" @change=\"toggleEdgeLabels\" />\r\n            显示连线标签\r\n          </label>\r\n        </div>\r\n\r\n        <!-- 拖动优化配置 -->\r\n        <div class=\"demo-performance__config-item\">\r\n          <label class=\"demo-performance__checkbox\">\r\n            <input type=\"checkbox\" v-model=\"enableDragOptimization\" checked />\r\n            启用拖动优化\r\n          </label>\r\n          <div class=\"demo-performance__hint\" style=\"margin-top: 4px;\">\r\n            拖动节点时自动简化连线渲染\r\n          </div>\r\n        </div>\r\n\r\n        <!-- 性能指标 -->\r\n        <div class=\"demo-performance__metrics\">\r\n          <h5 class=\"demo-performance__metrics-title\">性能指标</h5>\r\n          <div class=\"demo-performance__metric-item\">\r\n            <span class=\"demo-performance__metric-label\">数据生成耗时：</span>\r\n            <span class=\"demo-performance__metric-value\">{{ generateTime }}ms</span>\r\n          </div>\r\n          <div class=\"demo-performance__metric-item\">\r\n            <span class=\"demo-performance__metric-label\">节点渲染耗时：</span>\r\n            <span class=\"demo-performance__metric-value\">{{ nodeRenderTime }}ms</span>\r\n          </div>\r\n          <div class=\"demo-performance__metric-item\" v-if=\"showEdges && currentEdgeCount > 0\">\r\n            <span class=\"demo-performance__metric-label\">连线渲染耗时：</span>\r\n            <span class=\"demo-performance__metric-value\">{{ edgeRenderTime }}ms</span>\r\n          </div>\r\n          <div class=\"demo-performance__metric-item\">\r\n            <span class=\"demo-performance__metric-label\">渲染总耗时：</span>\r\n            <span class=\"demo-performance__metric-value\">{{ totalRenderTime }}ms</span>\r\n          </div>\r\n          <div class=\"demo-performance__metric-item\">\r\n            <span class=\"demo-performance__metric-label\">总耗时：</span>\r\n            <span class=\"demo-performance__metric-value\">{{ totalTime }}ms</span>\r\n          </div>\r\n          <div class=\"demo-performance__metric-item\">\r\n            <span class=\"demo-performance__metric-label\">当前节点数：</span>\r\n            <span class=\"demo-performance__metric-value\">{{ currentNodeCount }}</span>\r\n          </div>\r\n          <div class=\"demo-performance__metric-item\">\r\n            <span class=\"demo-performance__metric-label\">当前连线数：</span>\r\n            <span class=\"demo-performance__metric-value\">{{ currentEdgeCount }}</span>\r\n          </div>\r\n          <div class=\"demo-performance__metric-item\" v-if=\"isDragging\">\r\n            <span class=\"demo-performance__metric-label\">🔴 拖动中：</span>\r\n            <span class=\"demo-performance__metric-value performance-dragging\">{{ dragOptimizationStatus }}</span>\r\n          </div>\r\n        </div>\r\n\r\n        <!-- 操作按钮 -->\r\n        <div class=\"demo-performance__actions\">\r\n          <button\r\n            class=\"demo-performance__btn demo-performance__btn--secondary\"\r\n            @click=\"clearCanvas\"\r\n          >\r\n            清空画布\r\n          </button>\r\n          <button\r\n            class=\"demo-performance__btn demo-performance__btn--secondary\"\r\n            @click=\"fitView\"\r\n          >\r\n            适应画布\r\n          </button>\r\n        </div>\r\n      </div>\r\n    </div>\r\n\r\n    <!-- 画布容器 -->\r\n    <div class=\"demo-performance__canvas\">\r\n      <div class=\"demo-performance__tip\">\r\n        💡 性能测试 Demo - 测试大量节点的渲染性能。拖动优化已启用，拖动节点时会自动简化连线渲染。\r\n      </div>\r\n      <FlowDesignerLayout\r\n        ref=\"layoutRef\"\r\n        @ready=\"handleReady\"\r\n        :canvas-config=\"canvasConfig\"\r\n      >\r\n        <template #node-custom-nodetype1=\"{ node, graph, data, label, state }\">\r\n          <div class=\"cvn-task\" data-cvn-root :class=\"{ 'cvn-task--selected': node?.id == selectedNode?.id }\">\r\n            <div class=\"cvn-task__bar\" />\r\n            <div class=\"cvn-task__body\">\r\n              <!-- ✅ 新方式：使用响应式 label、data 和 state -->\r\n              <div class=\"cvn-task__title\">{{ label || '自定义vue插槽节点1' }}</div>\r\n              <div class=\"cvn-task__owner\">负责人：{{ data.owner || '未指定' }} state: {{ state }}</div>\r\n            </div>\r\n          </div>\r\n        </template>\r\n      </FlowDesignerLayout>\r\n    </div>\r\n  </div>\r\n</template>\r\n\r\n<script setup lang=\"ts\">\r\nimport { ref, computed, onMounted } from 'vue'\r\nimport { FlowDesignerLayout }  from '@quick-code/x6-flow-designer'\r\nimport type { FlowDesigner } from '@quick-code/x6-flow-designer'\r\nimport type { Graph } from '@antv/x6'\r\nimport { register } from '@antv/x6-vue-shape'\r\nimport VueNode1 from './components/vueNode1.vue'\r\n\r\n// 注册自定义 Vue 节点\r\nonMounted(() => {\r\n  register({\r\n    shape: 'vue-node-1',\r\n    component: VueNode1,\r\n    width: 120,\r\n    height: 60,\r\n  })\r\n  console.log('[自定义节点] vue-node-1 已注册')\r\n})\r\n\r\nconst layoutRef = ref()\r\nconst designerRef = ref<FlowDesigner>()\r\nconst graphRef = ref<Graph>()\r\n\r\n// 配置项\r\nconst nodeCount = ref(200)\r\nconst layoutType = ref<'grid' | 'circular' | 'random'>('grid')\r\nconst nodeType = ref<'rect' | 'circle' | 'common-vue-node' | 'vue-node-1'>('rect')\r\nconst showEdges = ref(true)\r\nconst showEdgeLabels = ref(true)\r\nconst enableDragOptimization = ref(true)\r\nconst isGenerating = ref(false)\r\n\r\n// 性能指标\r\nconst generateTime = ref(0)\r\nconst renderTime = ref(0)\r\nconst nodeRenderTime = ref(0)  // 节点渲染时长\r\nconst edgeRenderTime = ref(0)  // 连线渲染时长\r\nconst totalRenderTime = ref(0) // 渲染总时长（节点+连线）\r\nconst totalTime = ref(0)\r\nconst currentNodeCount = ref(0)\r\nconst currentEdgeCount = ref(0)\r\nconst dragOptimizationStatus = ref('')\r\n\r\n// 画布配置\r\nconst canvasConfig = ref({\r\n})\r\n\r\n// 生成随机颜色\r\nfunction getRandomColor(): string {\r\n  const colors = [\r\n    '#1890ff', '#52c41a', '#faad14', '#f5222d', '#722ed1',\r\n    '#13c2c2', '#eb2f96', '#fa8c16', '#a0d911', '#2f54eb',\r\n    '#fa541c', '#9254de', '#fadb14', '#096dd9', '#f759ab',\r\n  ]\r\n  return colors[Math.floor(Math.random() * colors.length)]\r\n}\r\n\r\n// 计算节点位置\r\nfunction calculateNodePosition(index: number, total: number, type: 'grid' | 'circular' | 'random') {\r\n  if (type === 'grid') {\r\n    const cols = Math.ceil(Math.sqrt(total))\r\n    const row = Math.floor(index / cols)\r\n    const col = index % cols\r\n    return {\r\n      x: 50 + col * 200,\r\n      y: 50 + row * 120,\r\n    }\r\n  } else if (type === 'circular') {\r\n    const radius = Math.min(total * 15, 800)\r\n    const angle = (index / total) * Math.PI * 2\r\n    return {\r\n      x: 1000 + radius * Math.cos(angle),\r\n      y: 800 + radius * Math.sin(angle),\r\n    }\r\n  } else {\r\n    // random\r\n    return {\r\n      x: Math.random() * 3000 + 100,\r\n      y: Math.random() * 2000 + 100,\r\n    }\r\n  }\r\n}\r\n\r\n// 生成节点\r\nasync function generateNodes() {\r\n  if (!graphRef.value || isGenerating.value) return\r\n\r\n  isGenerating.value = true\r\n  const startTime = performance.now()\r\n\r\n  try {\r\n    const graph = graphRef.value\r\n\r\n    // 🔴 修复：清空画布前先取消拖动优化\r\n    if (dragTimer.value !== null) {\r\n      clearTimeout(dragTimer.value)\r\n      dragTimer.value = null\r\n      console.log('[性能优化] 取消待执行的恢复定时器')\r\n    }\r\n    removedEdges.length = 0\r\n    isDragging.value = false\r\n    dragOptimizationStatus.value = ''\r\n\r\n    // 清空画布\r\n    graph.clearCells()\r\n\r\n    const generateStartTime = performance.now()\r\n\r\n    // 生成节点数据\r\n    const nodes = []\r\n    for (let i = 0; i < nodeCount.value; i++) {\r\n      const pos = calculateNodePosition(i, nodeCount.value, layoutType.value)\r\n      const color = getRandomColor()\r\n\r\n      let nodeData: any = {\r\n        id: `node-${i}`,\r\n        x: pos.x,\r\n        y: pos.y,\r\n        label: `节点 ${i + 1}`,\r\n        data: {\r\n          index: i,\r\n          color: color,\r\n        },\r\n      }\r\n\r\n      // 根据节点类型设置不同的 shape 和属性\r\n      if (nodeType.value === 'rect') {\r\n        nodeData.shape = 'rect'\r\n        nodeData.width = 120\r\n        nodeData.height = 60\r\n        nodeData.attrs = {\r\n          body: {\r\n            fill: color,\r\n            stroke: color,\r\n            strokeWidth: 2,\r\n            rx: 6,\r\n            ry: 6,\r\n          },\r\n          label: {\r\n            fill: '#fff',\r\n            fontSize: 12,\r\n            fontWeight: 'bold',\r\n          },\r\n        }\r\n      } else if (nodeType.value === 'circle') {\r\n        nodeData.shape = 'circle'\r\n        nodeData.width = 80\r\n        nodeData.height = 80\r\n        nodeData.attrs = {\r\n          body: {\r\n            fill: color,\r\n            stroke: color,\r\n            strokeWidth: 2,\r\n          },\r\n          label: {\r\n            fill: '#fff',\r\n            fontSize: 12,\r\n            fontWeight: 'bold',\r\n          },\r\n        }\r\n      } else if (nodeType.value === 'common-vue-node') {\r\n        nodeData.shape = 'common-vue-node'\r\n        nodeData['node-type'] = 'custom-nodetype1'\r\n        nodeData.width = 120\r\n        nodeData.height = 60\r\n        nodeData.attrs = {\r\n          body: {\r\n            fill: color,\r\n            stroke: color,\r\n            strokeWidth: 2,\r\n          },\r\n          label: {\r\n            fill: '#fff',\r\n            fontSize: 12,\r\n            fontWeight: 'bold',\r\n          },\r\n        }\r\n      } else if (nodeType.value === 'vue-node-1') {\r\n        nodeData.shape = 'vue-node-1'\r\n        nodeData.width = 120\r\n        nodeData.height = 60\r\n        nodeData.data = {\r\n          ...nodeData.data,\r\n          status: '运行中',\r\n        }\r\n      }\r\n\r\n      nodes.push(nodeData)\r\n    }\r\n\r\n    // 批量添加节点（使用事件监听统计真实渲染耗时）\r\n    let renderStartTime = 0\r\n    let nodesRendered = 0\r\n    const totalNodes = nodes.length\r\n\r\n    // 监听节点渲染完成\r\n    const nodeAddedHandler = () => {\r\n      if (nodesRendered === 0) {\r\n        renderStartTime = performance.now()\r\n        console.log('[渲染统计] 开始渲染节点，总数:', totalNodes)\r\n      }\r\n      nodesRendered++\r\n\r\n      if (nodesRendered === totalNodes) {\r\n        console.log('[渲染统计] 所有节点已添加到 graph，等待 DOM 渲染完成...')\r\n        // 移除监听器\r\n        graph.off('node:added', nodeAddedHandler)\r\n\r\n        // 等待浏览器完成渲染（使用双 RAF 确保渲染完成）\r\n        requestAnimationFrame(() => {\r\n          requestAnimationFrame(() => {\r\n            const nodeRenderDuration = performance.now() - renderStartTime\r\n            console.log('[渲染统计] 节点 DOM 渲染完成，耗时:', nodeRenderDuration.toFixed(2), 'ms')\r\n\r\n            // 记录节点渲染时长\r\n            nodeRenderTime.value = Math.round(nodeRenderDuration)\r\n\r\n            // 如果没有边，直接设置渲染时间\r\n            if (!showEdges.value || nodeCount.value <= 1) {\r\n              edgeRenderTime.value = 0\r\n              totalRenderTime.value = nodeRenderTime.value\r\n              renderTime.value = nodeRenderTime.value\r\n              updateFinalStats(graph, startTime)\r\n            } else {\r\n              // ✅ 节点渲染完成后，开始添加连线\r\n              addEdgesToGraph(graph, startTime, renderStartTime)\r\n            }\r\n          })\r\n        })\r\n      }\r\n    }\r\n\r\n    graph.on('node:added', nodeAddedHandler)\r\n    graph.addNodes(nodes)\r\n\r\n    generateTime.value = Math.round(performance.now() - generateStartTime)\r\n\r\n  } finally {\r\n    isGenerating.value = false\r\n  }\r\n}\r\n\r\n// 添加连线到画布（在节点渲染完成后调用）\r\nfunction addEdgesToGraph(graph: Graph, startTime: number, renderStartTime: number) {\r\n  const edgeStartTime = performance.now()\r\n  console.log('[渲染统计] 节点渲染完成，开始生成连线数据...')\r\n\r\n  const edges = []\r\n\r\n  // 主连线（链式连接）\r\n  for (let i = 0; i < nodeCount.value - 1; i++) {\r\n    const edgeData: any = {\r\n      id: `edge-${i}`,\r\n      source: `node-${i}`,\r\n      target: `node-${i + 1}`,\r\n      router: { name: 'metro', args: { padding: 20 } },\r\n      connector: { name: 'rounded', args: { radius: 8 } },\r\n      attrs: {\r\n        line: {\r\n          stroke: '#8c8c8c',\r\n          strokeWidth: 1,\r\n          targetMarker: {\r\n            name: 'classic',\r\n            size: 6,\r\n          },\r\n        },\r\n      },\r\n    }\r\n\r\n    // 如果启用了标签显示，添加 labels\r\n    if (showEdgeLabels.value) {\r\n      edgeData.labels = [`连线 ${i + 1}`]\r\n    }\r\n\r\n    edges.push(edgeData)\r\n  }\r\n\r\n  // 额外添加一些随机连线以增加复杂度\r\n  const extraEdgeCount = Math.min(Math.floor(nodeCount.value * 0.2), 100)\r\n  for (let i = 0; i < extraEdgeCount; i++) {\r\n    const sourceIndex = Math.floor(Math.random() * nodeCount.value)\r\n    const targetIndex = Math.floor(Math.random() * nodeCount.value)\r\n\r\n    if (sourceIndex !== targetIndex) {\r\n      const edgeData: any = {\r\n        id: `edge-extra-${i}`,\r\n        source: `node-${sourceIndex}`,\r\n        target: `node-${targetIndex}`,\r\n        router: { name: 'metro', args: { padding: 20 } },\r\n        connector: { name: 'rounded', args: { radius: 8 } },\r\n        attrs: {\r\n          line: {\r\n            stroke: '#d9d9d9',\r\n            strokeWidth: 1,\r\n            strokeDasharray: '5,5',\r\n            targetMarker: {\r\n              name: 'classic',\r\n              size: 5,\r\n            },\r\n          },\r\n        },\r\n      }\r\n\r\n      // 如果启用了标签显示，添加 labels\r\n      if (showEdgeLabels.value) {\r\n        edgeData.labels = [`额外 ${i + 1}`]\r\n      }\r\n\r\n      edges.push(edgeData)\r\n    }\r\n  }\r\n\r\n  console.log(`[渲染统计] 连线数据生成完成，耗时: ${Math.round(performance.now() - edgeStartTime)}ms，连线总数: ${edges.length}`)\r\n\r\n  // 批量添加连线（监听边渲染完成）\r\n  let edgeRenderStartTime = 0\r\n  const totalEdges = edges.length\r\n  let localEdgesRendered = 0\r\n\r\n  const edgeAddedHandler = () => {\r\n    if (localEdgesRendered === 0) {\r\n      edgeRenderStartTime = performance.now()\r\n      console.log('[渲染统计] 开始渲染连线，总数:', totalEdges)\r\n    }\r\n    localEdgesRendered++\r\n\r\n    if (localEdgesRendered === totalEdges) {\r\n      console.log('[渲染统计] 所有连线已添加到 graph，等待 DOM 渲染完成...')\r\n      // 移除监听器\r\n      graph.off('edge:added', edgeAddedHandler)\r\n\r\n      // 等待浏览器完成渲染\r\n      requestAnimationFrame(() => {\r\n        requestAnimationFrame(() => {\r\n          const edgeRenderDuration = performance.now() - edgeRenderStartTime\r\n          console.log('[渲染统计] 连线 DOM 渲染完成，耗时:', edgeRenderDuration.toFixed(2), 'ms')\r\n\r\n          // 记录连线渲染时长\r\n          edgeRenderTime.value = Math.round(edgeRenderDuration)\r\n\r\n          // 计算渲染总时长（从节点开始到连线结束）\r\n          const totalRenderDuration = performance.now() - renderStartTime\r\n          totalRenderTime.value = Math.round(totalRenderDuration)\r\n          renderTime.value = totalRenderTime.value // 保持兼容性\r\n\r\n          console.log('[渲染统计] 渲染总耗时:', totalRenderDuration.toFixed(2), 'ms')\r\n          console.log('[渲染统计] 验证：节点渲染 + 连线渲染 =', nodeRenderTime.value, '+', edgeRenderTime.value, '=', nodeRenderTime.value + edgeRenderTime.value, 'ms')\r\n\r\n          updateFinalStats(graph, startTime)\r\n        })\r\n      })\r\n    }\r\n  }\r\n\r\n  graph.on('edge:added', edgeAddedHandler)\r\n  graph.addEdges(edges)\r\n}\r\n\r\n// 更新最终统计信息（抽取为独立函数，避免重复代码）\r\nfunction updateFinalStats(graph: Graph, startTime: number) {\r\n  // 更新统计\r\n  currentNodeCount.value = graph.getNodes().length\r\n  currentEdgeCount.value = graph.getEdges().length\r\n\r\n  totalTime.value = Math.round(performance.now() - startTime)\r\n\r\n  console.log('[渲染统计] ========== 性能统计 ==========')\r\n  console.log('[渲染统计] 数据生成耗时:', generateTime.value, 'ms')\r\n  console.log('[渲染统计] 节点渲染耗时:', nodeRenderTime.value, 'ms')\r\n  console.log('[渲染统计] 连线渲染耗时:', edgeRenderTime.value, 'ms')\r\n  console.log('[渲染统计] 渲染总耗时:', totalRenderTime.value, 'ms')\r\n  console.log('[渲染统计] 总耗时:', totalTime.value, 'ms')\r\n  console.log('[渲染统计] 节点数:', currentNodeCount.value)\r\n  console.log('[渲染统计] 连线数:', currentEdgeCount.value)\r\n  console.log('[渲染统计] ================================')\r\n\r\n  // 自动适应画布\r\n  setTimeout(() => {\r\n    graph.zoomToFit({ padding: 20, maxScale: 1 })\r\n  }, 100)\r\n}\r\n\r\n// 切换连线显示\r\nfunction toggleEdges() {\r\n  if (!graphRef.value) return\r\n\r\n  const graph = graphRef.value\r\n  const edges = graph.getEdges()\r\n\r\n  if (showEdges.value) {\r\n    // 重新生成节点和连线\r\n    generateNodes()\r\n  } else {\r\n    // 删除所有连线\r\n    edges.forEach(edge => graph.removeEdge(edge))\r\n    currentEdgeCount.value = 0\r\n  }\r\n}\r\n\r\n// 切换连线标签显示\r\nfunction toggleEdgeLabels() {\r\n  if (!graphRef.value) return\r\n\r\n  const graph = graphRef.value\r\n  const edges = graph.getEdges()\r\n\r\n  edges.forEach((edge, index) => {\r\n    if (showEdgeLabels.value) {\r\n      edge.setLabels([{\r\n        attrs: {\r\n          label: {\r\n            text: `连线 ${index + 1}`,\r\n            fontSize: 10,\r\n            fill: '#595959',\r\n          },\r\n          rect: {\r\n            fill: '#ffffff',\r\n            stroke: '#d9d9d9',\r\n            strokeWidth: 1,\r\n            rx: 3,\r\n            ry: 3,\r\n          },\r\n        },\r\n      }])\r\n    } else {\r\n      edge.setLabels([])\r\n    }\r\n  })\r\n}\r\n\r\n// 清空画布\r\nfunction clearCanvas() {\r\n  if (!graphRef.value) return\r\n\r\n  // 取消拖动定时器，防止竞态条件\r\n  if (dragTimer.value) {\r\n    clearTimeout(dragTimer.value)\r\n    dragTimer.value = null\r\n  }\r\n\r\n  // 清空画布\r\n  graphRef.value.clearCells()\r\n\r\n  // 重置拖动优化状态\r\n  isDragging.value = false\r\n  removedEdges.length = 0\r\n  dragOptimizationStatus.value = ''\r\n\r\n  // 重置性能指标\r\n  currentNodeCount.value = 0\r\n  currentEdgeCount.value = 0\r\n  generateTime.value = 0\r\n  renderTime.value = 0\r\n  nodeRenderTime.value = 0\r\n  edgeRenderTime.value = 0\r\n  totalRenderTime.value = 0\r\n  totalTime.value = 0\r\n\r\n  console.log('[clearCanvas] 画布已清空，状态已重置')\r\n}\r\n\r\n// 适应画布\r\nfunction fitView() {\r\n  if (!graphRef.value) return\r\n  graphRef.value.zoomToFit({ padding: 20, maxScale: 1 })\r\n}\r\n\r\n// ==================== 拖动优化相关 ====================\r\n\r\n// 拖动优化状态\r\nconst isDragging = ref(false)\r\nconst dragTimer = ref<number | null>(null)\r\nconst removedEdges: any[] = [] // 存储被临时移除的边数据\r\nlet hasTriggeredOptimization = false // 标记本次拖动是否已触发优化\r\n\r\n// 边数量阈值配置（基于受影响的边数量）\r\nconst AFFECTED_EDGE_THRESHOLDS = {\r\n  LIGHT: 10,    // 少量受影响的边：切换路由\r\n  MEDIUM: 20,   // 中等受影响的边：局部移除\r\n  HEAVY: 100,   // 大量受影响的边：全量移除（兜底）\r\n}\r\n\r\n// 获取优化策略（基于受影响的边数量）\r\nfunction getOptimizationStrategy(affectedEdgeCount: number): 'switchRouter' | 'removeAffectedEdges' | 'removeAllEdges' {\r\n  if (affectedEdgeCount <= AFFECTED_EDGE_THRESHOLDS.LIGHT) {\r\n    return 'switchRouter'\r\n  } else if (affectedEdgeCount <= AFFECTED_EDGE_THRESHOLDS.MEDIUM) {\r\n    return 'removeAffectedEdges'\r\n  } else {\r\n    return 'removeAffectedEdges'\r\n  }\r\n}\r\n\r\n// 开始拖动优化\r\nfunction startDragOptimization() {\r\n  console.log('[DEBUG] startDragOptimization 被调用')\r\n  console.log('[DEBUG] graphRef.value:', !!graphRef.value, 'isDragging.value:', isDragging.value, 'enableDragOptimization.value:', enableDragOptimization.value)\r\n\r\n  if (!graphRef.value || isDragging.value || !enableDragOptimization.value) {\r\n    console.warn('[DEBUG] 提前返回，原因:', {\r\n      noGraph: !graphRef.value,\r\n      alreadyDragging: isDragging.value,\r\n      optimizationDisabled: !enableDragOptimization.value\r\n    })\r\n    return\r\n  }\r\n\r\n  const startTime = performance.now()\r\n  isDragging.value = true\r\n  const graph = graphRef.value\r\n\r\n  // ✅ 直接从 Selection 插件获取选中的节点（单一数据源，状态准确）\r\n  const selectedCells = graph.getSelectedCells()\r\n  console.log('[DEBUG] 从 Selection 获取的选中 cells:', selectedCells.length)\r\n\r\n  const movingNodes = selectedCells.filter(cell => cell.isNode())\r\n  console.log('[DEBUG] 过滤后的移动节点数:', movingNodes.length)\r\n\r\n  if (movingNodes.length === 0) {\r\n    console.warn('[性能优化] 没有找到选中的节点')\r\n    isDragging.value = false\r\n    return\r\n  }\r\n\r\n  console.log(`[性能优化] 开始拖动优化，移动节点数: ${movingNodes.length}`)\r\n\r\n  // 获取受影响的边（连接到移动节点的边）\r\n  const affectedEdgesSet = new Set<any>()\r\n  movingNodes.forEach(node => {\r\n    const connectedEdges = graph.getConnectedEdges(node)\r\n    console.log(`[DEBUG] 节点 ${node.id} 的连接边数:`, connectedEdges.length)\r\n    connectedEdges.forEach(edge => affectedEdgesSet.add(edge))\r\n  })\r\n\r\n  const affectedEdges = Array.from(affectedEdgesSet)\r\n  const totalEdges = graph.getEdges().length\r\n\r\n  console.log(`[性能优化] 受影响的边: ${affectedEdges.length} / ${totalEdges} (${((affectedEdges.length / totalEdges) * 100).toFixed(1)}%)`)\r\n\r\n  // 根据受影响的边数量选择策略\r\n  const strategy = getOptimizationStrategy(affectedEdges.length)\r\n  console.log('[性能优化] 选择策略:', strategy, '阈值配置:', AFFECTED_EDGE_THRESHOLDS)\r\n\r\n  // 清空之前的数据\r\n  removedEdges.length = 0\r\n\r\n  // 应用优化策略\r\n  if (strategy === 'removeAllEdges') {\r\n    // 策略 3: 移除所有边（兜底方案，用于极端情况）\r\n    console.log('[性能优化] 策略: 移除所有边（极端情况）')\r\n    dragOptimizationStatus.value = `已移除所有连线 (${totalEdges})`\r\n\r\n    const allEdges = graph.getEdges()\r\n    allEdges.forEach(edge => {\r\n      removedEdges.push({\r\n        id: edge.id,\r\n        source: edge.getSourceCellId(),\r\n        target: edge.getTargetCellId(),\r\n        router: edge.getRouter(),\r\n        connector: edge.getConnector(),\r\n        labels: edge.getLabels(),\r\n        attrs: edge.getAttrs(),\r\n        zIndex: edge.getZIndex(),\r\n        shape: edge.shape,\r\n      })\r\n    })\r\n    graph.removeCells(allEdges)\r\n    console.log('[性能优化] 已移除', removedEdges.length, '条边')\r\n  } else if (strategy === 'removeAffectedEdges') {\r\n    // 策略 2: 只移除受影响的边（推荐方案）⭐⭐⭐\r\n    console.log('[性能优化] 策略: 只移除受影响的边（局部优化）⭐')\r\n    dragOptimizationStatus.value = `已移除相关连线 (${affectedEdges.length}/${totalEdges})`\r\n\r\n    affectedEdges.forEach(edge => {\r\n      removedEdges.push({\r\n        id: edge.id,\r\n        source: edge.getSourceCellId(),\r\n        target: edge.getTargetCellId(),\r\n        router: edge.getRouter(),\r\n        connector: edge.getConnector(),\r\n        labels: edge.getLabels(),\r\n        attrs: edge.getAttrs(),\r\n        zIndex: edge.getZIndex(),\r\n        shape: edge.shape,\r\n      })\r\n    })\r\n    graph.removeCells(affectedEdges)\r\n    console.log('[性能优化] 已移除', removedEdges.length, '条受影响的边')\r\n  } else {\r\n    // 策略 1: 只切换路由（最轻量）\r\n    console.log('[性能优化] 策略: 切换受影响边的路由为 normal')\r\n    dragOptimizationStatus.value = `已简化路由 (${affectedEdges.length} 条边)`\r\n\r\n    affectedEdges.forEach(edge => {\r\n      removedEdges.push({\r\n        id: edge.id,\r\n        originalRouter: edge.getRouter(),\r\n      })\r\n      edge.setRouter({ name: 'normal' })\r\n    })\r\n    console.log('[性能优化] 已简化', affectedEdges.length, '条边的路由')\r\n  }\r\n\r\n  const elapsed = performance.now() - startTime\r\n  console.log(`[性能优化] 优化应用完成，耗时: ${elapsed.toFixed(2)}ms`)\r\n}\r\n\r\n// 结束拖动优化\r\nfunction endDragOptimization() {\r\n  if (!graphRef.value || !isDragging.value) return\r\n\r\n  // ✅ 重置优化标志\r\n  hasTriggeredOptimization = false\r\n\r\n  // 延迟恢复，避免连续拖动时频繁切换\r\n  if (dragTimer.value !== null) {\r\n    clearTimeout(dragTimer.value)\r\n  }\r\n\r\n  dragTimer.value = window.setTimeout(() => {\r\n    try {\r\n      const startTime = performance.now()\r\n      isDragging.value = false\r\n\r\n      const graph = graphRef.value\r\n      if (!graph) {\r\n        console.log('[endDragOptimization] Graph 已销毁，跳过恢复')\r\n        removedEdges.length = 0\r\n        dragOptimizationStatus.value = ''\r\n        return\r\n      }\r\n\r\n      // 判断策略：检查 removedEdges 中的数据结构\r\n      if (removedEdges.length > 0) {\r\n        const firstEdge = removedEdges[0]\r\n\r\n        if (firstEdge.source && firstEdge.target) {\r\n          // 策略 2 或 3: 边被移除了，需要重新添加\r\n          console.log('[性能优化] 恢复被移除的边，数量:', removedEdges.length)\r\n\r\n          // 批量添加回边\r\n          graph.addEdges(removedEdges)\r\n\r\n          const elapsed = performance.now() - startTime\r\n          console.log(`[性能优化] 已恢复 ${removedEdges.length} 条边，耗时: ${elapsed.toFixed(2)}ms`)\r\n\r\n          removedEdges.length = 0\r\n          dragTimer.value = null\r\n          dragOptimizationStatus.value = ''\r\n          return\r\n        } else if (firstEdge.originalRouter) {\r\n          // 策略 1: 只切换了路由，需要恢复路由\r\n          console.log('[性能优化] 恢复受影响边的路由，数量:', removedEdges.length)\r\n\r\n          let restoredCount = 0\r\n          removedEdges.forEach(edgeData => {\r\n            const edge = graph.getCellById(edgeData.id)\r\n            if (edge && edge.isEdge()) {\r\n              edge.setRouter(edgeData.originalRouter)\r\n              restoredCount++\r\n            }\r\n          })\r\n\r\n          const elapsed = performance.now() - startTime\r\n          console.log(`[性能优化] 已恢复 ${restoredCount} 条边的路由，耗时: ${elapsed.toFixed(2)}ms`)\r\n\r\n          removedEdges.length = 0\r\n          dragTimer.value = null\r\n          dragOptimizationStatus.value = ''\r\n          return\r\n        }\r\n      }\r\n\r\n      // 没有需要恢复的内容\r\n      console.log('[endDragOptimization] 无需恢复')\r\n      dragTimer.value = null\r\n      dragOptimizationStatus.value = ''\r\n\r\n    } catch (error) {\r\n      console.error('[endDragOptimization] 恢复配置时出错:', error)\r\n      // 出错时也要清理状态\r\n      removedEdges.length = 0\r\n      dragTimer.value = null\r\n      dragOptimizationStatus.value = ''\r\n      isDragging.value = false\r\n    }\r\n  }, 150) // 延迟 150ms 恢复\r\n}\r\n\r\n// 设置拖动优化监听器\r\nfunction setupDragOptimization(graph: Graph) {\r\n  let dragStartDistance = 0\r\n  let isMouseDown = false\r\n  let isDraggingNodes = false\r\n  const DRAG_THRESHOLD = 5 // 拖动距离阈值（像素）\r\n\r\n  // 监听节点移动开始\r\n  graph.on('node:mousedown', ({ node }) => {\r\n    isMouseDown = true\r\n    isDraggingNodes = false\r\n    // ✅ 重置计数器和标志\r\n    dragStartDistance = 0\r\n    hasTriggeredOptimization = false\r\n    console.log('[拖动优化] 开始按下节点:', node.id, '重置标志')\r\n  })\r\n\r\n  // 监听节点移动中\r\n  graph.on('node:change:position', ({ node }) => {\r\n    isDraggingNodes = true\r\n    console.log('[DEBUG] node:change:position 触发, node:', node.id, 'dragStartDistance:', dragStartDistance, 'hasTriggeredOptimization:', hasTriggeredOptimization, 'isDragging:', isDragging.value, 'isMouseDown:', isMouseDown)\r\n\r\n    // ✅ 只在本次拖动中触发一次优化（移除 isMouseDown 检查，因为框选后直接拖动不会触发 mousedown）\r\n    if (!hasTriggeredOptimization && !isDragging.value) {\r\n      dragStartDistance++\r\n      console.log('[DEBUG] dragStartDistance 递增到:', dragStartDistance, 'DRAG_THRESHOLD:', DRAG_THRESHOLD)\r\n      if (dragStartDistance > DRAG_THRESHOLD) {\r\n        hasTriggeredOptimization = true\r\n        console.log('[拖动优化] 触发优化，dragStartDistance:', dragStartDistance)\r\n        startDragOptimization()\r\n      }\r\n    }\r\n  })\r\n\r\n  // 监听节点移动结束\r\n  graph.on('node:moved', ({ node }) => {\r\n    console.log('[拖动优化] 节点移动结束:', node.id)\r\n\r\n    // 延迟检查，确保所有节点都停止移动\r\n    setTimeout(() => {\r\n      if (isDragging.value && !isMouseDown) {\r\n        console.log('[拖动优化] 所有节点停止移动，准备恢复')\r\n        endDragOptimization()\r\n      }\r\n    }, 50)\r\n  })\r\n\r\n  // 监听全局 mouseup（主要机制）\r\n  graph.on('blank:mouseup', () => {\r\n    console.log('[拖动优化] blank mouseup')\r\n    isMouseDown = false\r\n    if (isDragging.value && isDraggingNodes) {\r\n      isDraggingNodes = false\r\n      endDragOptimization()\r\n    }\r\n  })\r\n\r\n  // 监听节点 mouseup\r\n  graph.on('node:mouseup', ({ node }) => {\r\n    console.log('[拖动优化] 节点 mouseup:', node.id)\r\n    isMouseDown = false\r\n\r\n    // 延迟检查，确保所有拖动都已结束\r\n    setTimeout(() => {\r\n      if (isDragging.value && isDraggingNodes) {\r\n        console.log('[拖动优化] mouseup 后检查：准备恢复')\r\n        isDraggingNodes = false\r\n        endDragOptimization()\r\n      }\r\n    }, 50)\r\n  })\r\n\r\n  console.log('[性能优化] 拖动优化监听器已设置')\r\n}\r\n\r\n// 画布就绪\r\nfunction handleReady(designer: FlowDesigner, graph: Graph) {\r\n  designerRef.value = designer\r\n  graphRef.value = graph\r\n\r\n  // 设置拖动优化\r\n  setupDragOptimization(graph)\r\n\r\n  // 默认生成 200 个节点\r\n  generateNodes()\r\n}\r\n</script>\r\n\r\n<style scoped>\r\n.demo-performance {\r\n  display: flex;\r\n  width: 100%;\r\n  height: 100%;\r\n  background: #f5f5f5;\r\n  border-radius: 8px;\r\n  overflow: hidden;\r\n  box-shadow: 0 2px 8px rgba(0, 0, 0, 0.1);\r\n}\r\n\r\n/* ==================== 配置面板 ==================== */\r\n.demo-performance__panel {\r\n  width: 320px;\r\n  background: #fff;\r\n  border-right: 1px solid #e8e8e8;\r\n  display: flex;\r\n  flex-direction: column;\r\n}\r\n\r\n.demo-performance__panel-header {\r\n  padding: 16px 20px;\r\n  border-bottom: 1px solid #e8e8e8;\r\n  background: linear-gradient(180deg, #fafafa 0%, #f5f5f5 100%);\r\n}\r\n\r\n.demo-performance__panel-header h4 {\r\n  margin: 0;\r\n  font-size: 16px;\r\n  font-weight: 600;\r\n  color: #1a1a2e;\r\n}\r\n\r\n.demo-performance__panel-content {\r\n  flex: 1;\r\n  padding: 20px;\r\n  overflow-y: auto;\r\n}\r\n\r\n/* ==================== 配置项 ==================== */\r\n.demo-performance__config-item {\r\n  margin-bottom: 20px;\r\n}\r\n\r\n.demo-performance__label {\r\n  display: block;\r\n  font-size: 13px;\r\n  font-weight: 500;\r\n  color: #333;\r\n  margin-bottom: 8px;\r\n}\r\n\r\n.demo-performance__input-group {\r\n  display: flex;\r\n  gap: 8px;\r\n}\r\n\r\n.demo-performance__input {\r\n  flex: 1;\r\n  padding: 8px 12px;\r\n  border: 1px solid #d