ce__metrics {\r\n  padding: 16px;\r\n  background: #f9fafb;\r\n  border: 1px solid #e8e8e8;\r\n  border-radius: 6px;\r\n  margin-bottom: 20px;\r\n}\r\n\r\n.demo-performance__metrics-title {\r\n  margin: 0 0 12px 0;\r\n  font-size: 14px;\r\n  font-weight: 600;\r\n  color: #333;\r\n}\r\n\r\n.demo-performance__metric-item {\r\n  display: flex;\r\n  justify-content: space-between;\r\n  align-items: center;\r\n  padding: 6px 0;\r\n  font-size: 13px;\r\n}\r\n\r\n.demo-performance__metric-label {\r\n  color: #666;\r\n}\r\n\r\n.demo-performance__metric-value {\r\n  font-weight: 600;\r\n  color: #1890ff;\r\n  font-family: 'Courier New', monospace;\r\n}\r\n\r\n.demo-performance__metric-value.performance-dragging {\r\n  color: #ff4d4f;\r\n  animation: pulse 1.5s ease-in-out infinite;\r\n}\r\n\r\n@keyframes pulse {\r\n  0%, 100% {\r\n    opacity: 1;\r\n  }\r\n  50% {\r\n    opacity: 0.6;\r\n  }\r\n}\r\n\r\n/* ==================== 操作按钮区 ==================== */\r\n.demo-performance__actions {\r\n  margin-top: 20px;\r\n  padding-top: 20px;\r\n  border-top: 1px solid #e8e8e8;\r\n}\r\n\r\n/* ==================== 画布容器 ==================== */\r\n.demo-performance__canvas {\r\n  flex: 1;\r\n  display: flex;\r\n  flex-direction: column;\r\n  background: #fff;\r\n  position: relative;\r\n}\r\n\r\n.demo-performance__tip {\r\n  padding: 12px 16px;\r\n  background: #e6f4ff;\r\n  border-bottom: 1px solid #91caff;\r\n  color: #0958d9;\r\n  font-size: 13px;\r\n  line-height: 1.6;\r\n}\r\n\r\n/* ==================== 自定义节点样式 ==================== */\r\n/* 任务节点样式 */\r\n.cvn-task {\r\n  display: flex;\r\n  flex-direction: column;\r\n  width: 160px;\r\n  background: #fff;\r\n  border: 1.5px solid #e8e8e8;\r\n  border-radius: 8px;\r\n  overflow: hidden;\r\n  box-shadow: 0 2px 8px rgba(0, 0, 0, 0.08);\r\n  user-select: none;\r\n  transition: border-color 0.2s, box-shadow 0.2s;\r\n}\r\n\r\n.cvn-task:hover {\r\n  border-color: #ffa940;\r\n}\r\n\r\n.cvn-task--selected {\r\n  border: 3px solid #fa8c16;\r\