<template>
  <div class="demo-slot-edge-tooltip">
    <!-- 事件日志面板 -->
    <div class="demo-slot-edge-tooltip__log">
      <div class="demo-slot-edge-tooltip__log-header">
        <h4>事件日志</h4>
        <button class="demo-slot-edge-tooltip__clear-btn" @click="clearLogs" title="清除日志">
          清除
        </button>
      </div>
      <div class="demo-slot-edge-tooltip__log-content">
        <div v-for="(log, index) in logs" :key="index" class="demo-slot-edge-tooltip__log-item">
          {{ log }}
        </div>
        <div v-if="logs.length === 0" class="demo-slot-edge-tooltip__log-empty">
          将鼠标悬停在连线上以查看自定义 Tooltip
        </div>
      </div>
    </div>

    <!-- 画布容器 -->
    <div class="demo-slot-edge-tooltip__canvas">
      <FlowDesignerLayout
        mode="design"
        :permission-config="permissionConfig"
        :before-graph-init="handleBeforeGraphInit"
        @ready="handleReady"
      >
            <template #edge-tooltip="{ edge, data }">
              <div class="my-edge-tooltip">
                edge-tooltip插槽:{{ data?.label }}
              </div>
            </template>
      </FlowDesignerLayout>
    </div>
  </div>
</template>

<script setup lang="ts">
import { ref, reactive } from 'vue'
import { FlowDesignerLayout }  from '@quick-code/x6-flow-designer'
import type { FlowDesigner } from '@quick-code/x6-flow-designer'
import type { Graph, Edge, Node } from '@antv/x6'
import {FlowDesignerOptions} from "@/components/FlowDesigner/core/FlowDesigner";

// ============================================================================
// 状态管理
// ============================================================================

const logs = ref<string[]>([])
let designer: FlowDesigner | null = null
let graph: Graph | null = null

// 权限配置 - 启用 Edge Tooltip
const permissionConfig = reactive({
  design: {
    showToolbar: false,
    showNodePalette: false,
    showPropertiesPanel: false,
    showContextMenu: false,
    canEdgeTooltip: true, // 启用连线 Tooltip
    canHoverEdge: true,   // 启用连线悬停
  },
})

// ============================================================================
// 工具函数
// ============================================================================

/**
 * 获取连线图标
 */
function getEdgeIcon(connectorName?: string): string {
  const iconMap: Record<string, string> = {
    'smooth': '〜',
    'rounded': '⌒',
    'normal': '—',
  }
  return iconMap[connectorName || ''] || '→'
}

/**
 * 获取连接器名称
 */
function getConnectorName(connectorName?: string): string {
  const nameMap: Record<string, string> = {
    'smooth': '平滑曲线',
    'rounded': '圆角折线',
    'normal': '直线',
  }
  return nameMap[connectorName || ''] || connectorName || '默认'
}

/**
 * 获取节点标签
 */
function getNodeLabel(node: Node | null): string {
  if (!node) return '未知节点'
  const label = node.getProp('label') || node.getData()?.label
  return label || node.id.substring(0, 8)
}

/**
 * 添加日志
 */
function addLog(message: string) {
  const timestamp = new Date().toLocaleTimeString('zh-CN', { hour12: false })
  logs.value.push(`[${timestamp}] ${message}`)

  // 自动滚动到底部
  setTimeout(() => {
    const logContent = document.querySelector('.demo-slot-edge-tooltip__log-content')
    if (logContent) {
      logContent.scrollTop = logContent.scrollHeight
    }
  }, 10)
}

/**
 * 清除日志
 */
function clearLogs() {
  logs.value = []
  addLog('日志已清除')
}

// ============================================================================
// 事件处理
// ============================================================================

/**
 * Tooltip 显示时触发
 */
function handleTooltipShow(edge: Edge, data: any) {
  const label = data?.label || '连接线'
  const sourceLabel = getNodeLabel(edge.getSourceNode())
  const targetLabel = getNodeLabel(edge.getTargetNode())
  addLog(`显示连线 Tooltip: ${label} (${sourceLabel} → ${targetLabel})`)
}

/**
 * FlowDesigner 准备完成
 */
function handleReady(designerInstance: FlowDesigner) {
  designer = designerInstance
  graph = designer.getGraph()

  addLog('FlowDesigner 初始化完成')
  addLog('✨ 将鼠标悬停在连线上查看自定义 Tooltip')

  // 初始化测试数据
  initTestData(graph)
}

/**
 * 初始化测试数据
 */
function initTestData(graph) {
  if (!designer) return

  // 添加初始节点
  const node1 = graph.addNode({
    shape: 'custom-circle',
    x: 100,
    y: 100,
    label: '开始',
    data: {
      description: '流程开始节点',
      owner: '张三',
      priority: 'high',
    },
  })

  const node2 = graph.addNode({
    shape: 'custom-rect',
    x: 300,
    y: 100,
    label: '处理',
    data: {
      description: '执行业务处理',
      owner: '李四',
      priority: 'medium',
    },
  })

  const node3 = graph.addNode({
    shape: 'custom-circle',
    x: 500,
    y: 100,
    label: '结束',
    data: {
      description: '流程结束',
      owner: '王五',
      priority: 'low',
    },
  })

  // 添加连线
  graph.addEdge({
    source: node1,
    target: node2,
    shape: 'flow-edge',
    labels: [{ attrs: { text: { text: '通过' } } }],
    data: {
      lineType: 'normal',
      condition: 'status === "approved"',
      description: '审批通过后的流转',
      isDefault: false,
    },
  })

  graph.addEdge({
    source: node2,
    target: node3,
    shape: 'flow-edge',
    labels: [{ attrs: { text: { text: '完成' } } }],
    data: {
      lineType: 'normal',
      condition: '',
      description: '处理完成后结束',
      isDefault: true,
    },
  })
}

/**
 * Graph 初始化前的配置（注册自定义节点样式）
 */
function handleBeforeGraphInit({Graph}) {
  // 注册自定义节点：蓝色圆形
  Graph.registerNode('custom-circle', {
    inherit: 'circle',
    width: 100,
    height: 100,
    attrs: {
      body: {
        fill: '#5F95FF',
        stroke: '#2563EB',
        strokeWidth: 2,
      },
      label: {
        fill: '#fff',
        fontSize: 14,
        fontWeight: 500,
      },
    },
  }, true)

  Graph.registerNode('custom-rect', {
    inherit: 'rect',
    width: 140,
    height: 70,
    attrs: {
      body: {
        fill: '#47C769',
        stroke: '#27AE60',
        strokeWidth: 2,
        rx: 8,
        ry: 8,
      },
      label: {
        fill: '#fff',
        fontSize: 14,
        fontWeight: 500,
      },
    },
  }, true)
}
</script>

<style scoped>
/* ═══════════════════════════════════════════════════════════════════════════
   容器布局
   ═══════════════════════════════════════════════════════════════════════════ */
.demo-slot-edge-tooltip {
  display: flex;
  height: 500px;
  background: #f5f6fa;
  border-radius: 8px;
  overflow: hidden;
  box-shadow: 0 2px 8px rgba(0, 0, 0, 0.1);
}

/* ═══════════════════════════════════════════════════════════════════════════
   事件日志面板
   ═══════════════════════════════════════════════════════════════════════════ */
.demo-slot-edge-tooltip__log {
  width: 320px;
  display: flex;
  flex-direction: column;
  padding: 16px;
  background: #fafafa;
  overflow: hidden;
  border-right: 1px solid #e8e8e8;
}

.demo-slot-edge-tooltip__log-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 12px;
}

.demo-slot-edge-tooltip__log-header h4 {
  margin: 0;
  font-size: 14px;
  color: #1a1a2e;
  font-weight: 600;
}

.demo-slot-edge-tooltip__clear-btn {
  padding: 2px 8px;
  font-size: 12px;
  color: #666;
  background: #fff;
  border: 1px solid #d9d9d9;
  border-radius: 4px;
  cursor: pointer;
  transition: all 0.2s;
  user-select: none;
}

.demo-slot-edge-tooltip__clear-btn:hover {
  color: #1890ff;
  border-color: #1890ff;
}

.demo-slot-edge-tooltip__log-content {
  flex: 1;
  overflow-y: auto;
  font-size: 12px;
  line-height: 1.8;
}

.demo-slot-edge-tooltip__log-item {
  padding: 4px 0;
  color: #555;
  font-family: 'Monaco', 'Menlo', 'Consolas', monospace;
  border-bottom: 1px solid #f0f0f0;
}

.demo-slot-edge-tooltip__log-empty {
  padding: 20px;
  text-align: center;
  color: #999;
  font-size: 13px;
  line-height: 1.6;
}

/* ═══════════════════════════════════════════════════════════════════════════
   画布容器
   ═══════════════════════════════════════════════════════════════════════════ */
.demo-slot-edge-tooltip__canvas {
  flex: 1;
  position: relative;
  background: #ffffff;
  overflow: hidden;
}

/* ═══════════════════════════════════════════════════════════════════════════
   自定义连线 Tooltip 样式
   ═══════════════════════════════════════════════════════════════════════════ */
.my-edge-tooltip {
  background: #fff;
  border: 1px solid #e8e8e8;
  border-radius: 4px;
  padding: 8px;
  box-shadow: 0 2px 8px rgba(0, 0, 0, 0.15);
}
</style>
