<template>
  <FlowDesignerLayout
    @ready="handleReady"
  />
</template>

<script setup lang="ts">
import { message } from 'ant-design-vue'
import { FlowDesignerLayout }  from '@quick-code/x6-flow-designer'
import type { FlowDesigner } from '@quick-code/x6-flow-designer'
import type { Edge } from '@antv/x6'

/**
 * ready 回调：覆盖内置连线状态并初始化画布
 */
function handleReady(designer: FlowDesigner) {
  const graph = designer.getGraph()

  // ========== 覆盖 5 种内置连线状态 ==========

  // 1. 覆盖 default 状态：淡紫色虚线
  designer.registerEdgeStateHandler('default', {
    apply(edge) {
      edge.setAttrs({
        line: {
          stroke: '#9333ea',
          strokeWidth: 2,
          //strokeDasharray: '4,4',
        }
      })
      edge.setLabelAt(0, {
        attrs: {
          label: {
            fill: '#6b21a8',
            text: '自定义默认',
          },
          rect: {
            fill: '#f3e8ff',
            stroke: '#9333ea',
            strokeWidth: 2,
          }
        }
      })
    }
  })

  // 2. 覆盖 hover 状态：橙色加粗 + 阴影效果
  designer.registerEdgeStateHandler('hover', {
    apply(edge) {
      edge.setAttrs({
        line: {
          stroke: '#f97316',
          strokeWidth: 4,
          filter: {
            name: 'dropShadow',
            args: { dx: 0, dy: 2, blur: 4, color: 'rgba(249, 115, 22, 0.5)' }
          }
        }
      })
      edge.setLabelAt(0, {
        attrs: {
          label: {
            fill: '#9a3412',
            text: '悬停效果',
            fontWeight: 'bold',
          },
          rect: {
            fill: '#fed7aa',
            stroke: '#f97316',
            strokeWidth: 2,
          }
        }
      })
    },
    cleanup(edge) {
      edge.setAttrs({
        line: {
          filter: null
        }
      })
    }
  })

  // 3. 覆盖 selected 状态：青色粗线 + 光晕
  designer.registerEdgeStateHandler('selected', {
    apply(edge) {
      edge.setAttrs({
        line: {
          stroke: '#06b6d4',
          strokeWidth: 3,
        }
      })
      edge.setLabelAt(0, {
        attrs: {
          label: {
            fill: '#164e63',
            text: '已选中',
            fontWeight: 'bold',
            fontSize: 14,
          },
          rect: {
            fill: '#cffafe',
            stroke: '#06b6d4',
            strokeWidth: 3,
          }
        }
      })
    },
    cleanup(edge) {
      edge.setAttrs({
        line: {
          filter: null
        }
      })
    }
  })

  // 4. 覆盖 flowing 状态：粉色渐变 + CSS 流动动画
  designer.registerEdgeStateHandler('flowing', {
    apply(edge) {
      edge.setAttrs({
        line: {
          stroke: '#ec4899',
          strokeWidth: 3,
          strokeDasharray: '10,5',
          // ✅ 使用 CSS animation 替代 setInterval，避免定时器泄漏
          style: {
            animation: 'fd-flow 1s linear infinite'
          }
        }
      })
      edge.setLabelAt(0, {
        attrs: {
          label: {
            fill: '#831843',
            text: '数据流动中',
            fontStyle: 'italic',
          },
          rect: {
            fill: '#fce7f3',
            stroke: '#ec4899',
            strokeWidth: 2,
          }
        }
      })
    },
    cleanup(edge) {
      // 停止 CSS 动画
      edge.setAttrs({
        line: {
          strokeDasharray: 0,
          style: {
            animation: 'none'
          }
        }
      })
    }
  })

  // 5. 覆盖 dimmed 状态：深灰色半透明 + 模糊
  designer.registerEdgeStateHandler('dimmed', {
    apply(edge) {
      edge.setAttrs({
        line: {
          stroke: '#4b5563',
          strokeWidth: 1,
          opacity: 0.3,
          filter: {
            name: 'blur',
            args: { stdDeviation: 1 }
          }
        }
      })
      edge.setLabelAt(0, {
        attrs: {
          label: {
            fill: '#6b7280',
            text: '已弱化',
            fontStyle: 'italic',
            fontSize: 11,
          },
          rect: {
            fill: '#f3f4f6',
            stroke: '#9ca3af',
            strokeWidth: 1,
            opacity: 0.5,
          }
        }
      })
    },
    cleanup(edge) {
      edge.setAttrs({
        line: {
          opacity: 1,
          filter: null
        }
      })
    }
  })

  // ========== 创建演示节点 ==========

  const startNode = graph.addNode({
    id: 'start',
    shape: 'rect',
    x: 80,
    y: 120,
    width: 100,
    height: 60,
    label: '开始',
    attrs: {
      body: {
        stroke: '#5b8ff9',
        strokeWidth: 2,
        fill: '#e6f4ff',
      },
      label: {
        fill: '#003a8c',
        fontSize: 14,
      },
    },
  })

  const node1 = graph.addNode({
    id: 'node1',
    shape: 'rect',
    x: 280,
    y: 40,
    width: 100,
    height: 60,
    label: '任务 A',
    attrs: {
      label: {
        fontSize: 14,
      },
    },
  })

  const node2 = graph.addNode({
    id: 'node2',
    shape: 'rect',
    x: 280,
    y: 140,
    width: 100,
    height: 60,
    label: '任务 B',
    attrs: {
      label: {
        fontSize: 14,
      },
    },
  })

  const node3 = graph.addNode({
    id: 'node3',
    shape: 'rect',
    x: 480,
    y: 40,
    width: 100,
    height: 60,
    label: '任务 C',
    attrs: {
      label: {
        fontSize: 14,
      },
    },
  })

  const node4 = graph.addNode({
    id: 'node4',
    shape: 'rect',
    x: 480,
    y: 140,
    width: 100,
    height: 60,
    label: '任务 D',
    attrs: {
      label: {
        fontSize: 14,
      },
    },
  })

  const endNode = graph.addNode({
    id: 'end',
    shape: 'rect',
    x: 680,
    y: 120,
    width: 100,
    height: 60,
    label: '结束',
    attrs: {
      body: {
        stroke: '#5b8ff9',
        strokeWidth: 2,
        fill: '#e6f4ff',
      },
      label: {
        fill: '#003a8c',
        fontSize: 14,
      },
    },
  })

  // ========== 创建演示连线（展示 5 种覆盖的内置状态）==========

  const edge1 = graph.addEdge({
    id: 'edge1',
    shape: 'flow-edge',
    source: startNode,
    target: node1,
    labels: ['默认状态'],
  })
  designer.setEdgeState(edge1, 'default')

  const edge2 = graph.addEdge({
    id: 'edge2',
    shape: 'flow-edge',
    source: startNode,
    target: node2,
    labels: ['悬停状态'],
  })
  designer.setEdgeState(edge2, 'default')

  const edge3 = graph.addEdge({
    id: 'edge3',
    shape: 'flow-edge',
    source: node1,
    target: node3,
    labels: ['选中状态'],
  })
  designer.setEdgeState(edge3, 'default')

  const edge4 = graph.addEdge({
    id: 'edge4',
    shape: 'flow-edge',
    source: node2,
    target: node4,
    labels: ['流动状态'],
  })
  designer.setEdgeState(edge4, 'default')

  const edge5 = graph.addEdge({
    id: 'edge5',
    shape: 'flow-edge',
    source: node3,
    target: endNode,
    labels: ['弱化状态'],
  })
  designer.setEdgeState(edge5, 'default')

  const edge6 = graph.addEdge({
    id: 'edge6',
    shape: 'flow-edge',
    source: node4,
    target: endNode,
    labels: ['默认状态2'],
  })
  designer.setEdgeState(edge6, 'default')

  // 居中显示
  graph.centerContent()

  // ========== 添加交互：点击连线切换状态 ==========

  const states = ['default', 'hover', 'selected', 'flowing', 'dimmed']
  const stateMap = new Map<string, number>() // 记录每条边的当前状态索引


  console.log('[Demo] 连线状态管理示例已加载（覆盖内置状态）')
  message.success('已覆盖 5 种内置连线状态，点击连线切换状态')
}
</script>
