  padding: 16px;
  background: #fafafa;
  overflow: hidden;
  display: flex;
  flex-direction: column;
}

.demo-node-lifecycle__log-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 12px;
}

.demo-node-lifecycle__log h4 {
  margin: 0;
  font-size: 14px;
  color: #1a1a2e;
  font-weight: 600;
}

.demo-node-lifecycle__clear-btn {
  padding: 2px 8px;
  font-size: 12px;
  color: #666;
  background: #fff;
  border: 1px solid #d9d9d9;
  border-radius: 4px;
  cursor: pointer;
  transition: all 0.2s;
  user-select: none;
}

.demo-node-lifecycle__clear-btn:hover {
  color: #1890ff;
  border-color: #1890ff;
}

.demo-node-lifecycle__log-content {
  flex: 1;
  overflow-y: auto;
  font-size: 12px;
  line-height: 1.8;
}

.demo-node-lifecycle__log-item {
  padding: 4px 0;
  color: #555;
  font-family: 'Monaco', 'Menlo', 'Consolas', monospace;
  border-bottom: 1px solid #f0f0f0;
}

.demo-node-lifecycle__log-item:last-child {
  border-bottom: none;
}

.demo-node-lifecycle__canvas {
  flex: 1;
  border: 1px solid #e8e8e8;
